import React, { useState, useEffect } from 'react';
import { AnimatePresence } from 'framer-motion';
import { 
  onAuthStateChanged,
  User,
  fetchFullUserDashboard,
  syncDailyActivity
} from './services/supabase';

import Navigation from './components/Navigation';
import Dashboard from './components/Dashboard';
import FoodLens from './components/FoodLens';
import BMIHub from './components/BMIHub';
import MapTrackingScreen from './components/MapTrackingScreen';
import ChatBot from './components/ChatBot';
import ProfileScreen from './components/ProfileScreen';
import OnboardingScreen from './components/OnboardingScreen'; 
import Auth from './components/Auth';
import { ViewState, ActivityData, FoodHistoryItem, UserMetrics } from './types';
import useLocalStorage from './hooks/useLocalStorage';
import usePedometer from './hooks/usePedometer';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [userProfile, setUserProfile] = useState<any>(null);
  const [isAuthChecking, setIsAuthChecking] = useState(true); 
  const [isProfileChecking, setIsProfileChecking] = useState(false);

  // --- THE LOADING LOCK (Safety Gate) ---
  const [isInitialLoadComplete, setIsInitialLoadComplete] = useState(false);

  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);
  const { isTracking, toggleTracking, liveSteps, resetLiveSteps } = usePedometer();

  const [activityData, setActivityData] = useState<ActivityData>({
    steps: 0, calories: 0, distance: 0, stepGoal: 10000, calorieGoal: 2000, distanceGoal: 5.0, history: []
  });

  const [bmiMetrics, setBmiMetrics] = useLocalStorage<UserMetrics>('bmi_metrics', { height: 175, weight: 70 });
  const [foodHistory, setFoodHistory] = useLocalStorage<FoodHistoryItem[]>('food_history', []);
  const [adaptiveGoalsEnabled, setAdaptiveGoalsEnabled] = useLocalStorage<boolean>('adaptive_goals_enabled', true);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(async (user) => {
      setIsInitialLoadComplete(false);

      if (user) {
        setCurrentUser(user);
        setIsProfileChecking(true);

        try {
          // fetchFullUserDashboard is now robust against PGRST205 errors
          const dashboardData = await fetchFullUserDashboard(user.id);

          if (dashboardData) {
              if (dashboardData.profile) setUserProfile(dashboardData.profile);

              setActivityData(prev => ({
                ...prev,
                steps: dashboardData.todayActivity?.steps || 0,
                calories: dashboardData.todayActivity?.calories_burned || 0,
                stepGoal: dashboardData.profile?.goals?.stepGoal || prev.stepGoal,
                calorieGoal: dashboardData.profile?.goals?.calorieGoal || prev.calorieGoal
              }));
          }
        } catch (e) {
          console.error("Critical Profile Load Failure:", e);
        } finally {
          // Safety: Release the loading lock no matter what happens
          setIsInitialLoadComplete(true);
          setIsProfileChecking(false);
        }
      } else { 
        setCurrentUser(null); 
        setUserProfile(null);
        setIsInitialLoadComplete(false);
      }
      setIsAuthChecking(false);
    });
    return () => { if (unsubscribe) unsubscribe(); };
  }, []);

  useEffect(() => {
    if (!currentUser || !isInitialLoadComplete) return;

    if (liveSteps > 0) {
       setActivityData(prev => {
          const newSteps = prev.steps + liveSteps;
          const newCals = prev.calories + (liveSteps * 0.04);
          syncDailyActivity(currentUser.id, newSteps, Math.floor(newCals), prev.stepGoal);
          return { ...prev, steps: newSteps, calories: newCals };
       });
       resetLiveSteps();
    }
  }, [liveSteps, currentUser, isInitialLoadComplete, resetLiveSteps]);

  const handleUpdateGoals = (newGoals: Partial<ActivityData>) => setActivityData(prev => ({ ...prev, ...newGoals }));

  if (isAuthChecking) return <div className="h-screen bg-black flex items-center justify-center text-luxury-neon animate-pulse text-[10px] uppercase tracking-[0.3em]">Initialising Ecosystem...</div>;
  if (!currentUser) return <Auth onLoginSuccess={() => {}} />;
  if (isProfileChecking) return <div className="h-screen bg-black flex items-center justify-center text-gray-400 text-[10px] uppercase tracking-[0.3em]">Synchronizing Records...</div>;

  if (!userProfile) {
     return <OnboardingScreen user={currentUser} onComplete={(p) => { setUserProfile(p); setCurrentView(ViewState.DASHBOARD); }} />;
  }

  return (
    <div className="flex flex-col h-[100dvh] bg-black text-white relative overflow-hidden font-sans">
      <main className="flex-1 relative w-full overflow-hidden">
        <AnimatePresence mode="wait">
          {currentView === ViewState.DASHBOARD && (
            <Dashboard 
              key="dash" 
              data={activityData} 
              onUpdateGoals={handleUpdateGoals} 
              isTracking={isTracking} 
              onToggleTracking={toggleTracking} 
              foodHistory={foodHistory}
              adaptiveGoalsEnabled={adaptiveGoalsEnabled}
              onToggleAdaptiveGoals={setAdaptiveGoalsEnabled}
            />
          )}
          {currentView === ViewState.CHAT && <ChatBot key="chat" metrics={bmiMetrics} activity={activityData} />}
          {currentView === ViewState.FOOD_LENS && <FoodLens key="lens" history={foodHistory} onAddToHistory={h => setFoodHistory([h, ...foodHistory])} />}
          {currentView === ViewState.BMI_HUB && <BMIHub key="bmi" />}
          {currentView === ViewState.MAP_TRACKER && <MapTrackingScreen key="map" userHeight={bmiMetrics.height} />}
          {currentView === ViewState.PROFILE && <ProfileScreen key="profile" onUpdateMetrics={setBmiMetrics} />}
        </AnimatePresence>
      </main>
      <Navigation currentView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

import { GoogleGenAI, Type, Content } from "@google/genai";
import { FoodAnalysis, UserMetrics, ActivityData, WorkoutPlan } from "../types";

// Initialize the Google GenAI client with correct guidelines
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const foodResponseSchema = {
  type: Type.OBJECT,
  properties: {
    name: { type: Type.STRING, description: "Name of the food item" },
    macros: {
      type: Type.OBJECT,
      properties: {
        calories: { type: Type.NUMBER },
        protein: { type: Type.NUMBER },
        fat: { type: Type.NUMBER },
        carbs: { type: Type.NUMBER },
      },
      required: ["calories", "protein", "fat", "carbs"]
    },
    healthScore: { type: Type.NUMBER, description: "Score from 0-100" },
    verdict: { type: Type.STRING, enum: ["Excellent", "Good", "Fair", "Avoid"] },
    advice: { type: Type.STRING, description: "Short nutritional tip" },
    alternatives: { type: Type.STRING, description: "A healthier alternative or modification to this meal." },
    colorCode: { type: Type.STRING, enum: ["green", "yellow", "red"] },
  },
  required: ["name", "macros", "healthScore", "verdict", "advice", "alternatives", "colorCode"]
};

const workoutResponseSchema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING, description: "Catchy name for the workout" },
    difficulty: { type: Type.STRING },
    duration: { type: Type.STRING, description: "Estimated time e.g. '45 mins'" },
    exercises: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          sets: { type: Type.STRING },
          reps: { type: Type.STRING },
          notes: { type: Type.STRING, description: "Form tip or tempo instruction" }
        },
        required: ["name", "sets", "reps", "notes"]
      }
    }
  },
  required: ["title", "difficulty", "duration", "exercises"]
};

const checkInExtractionSchema = {
  type: Type.OBJECT,
  properties: {
    tasksCompleted: { type: Type.BOOLEAN, description: "True if user said yes to finishing tasks/workout." },
    newWeight: { type: Type.NUMBER, description: "The numeric weight value provided by user, if any." },
    newHeight: { type: Type.NUMBER, description: "The numeric height value provided by user, if any." },
    replyMessage: { type: Type.STRING, description: "A short, encouraging response from the coach." }
  },
  required: ["replyMessage"]
};

const handleGenAIError = (error: any): never => {
  console.error("Gemini API Error:", error);
  let message = "AI Service Unavailable. Please retry.";
  const errString = error.toString().toLowerCase();
  if (errString.includes('api_key') || error.status === 403) message = "System Configuration Error: API Key invalid.";
  else if (errString.includes('429')) message = "High Traffic Volume. Please try again in a moment.";
  else if (errString.includes('blocked')) message = "Analysis blocked by safety filters.";
  throw new Error(message);
};

// FAST RESPONSE: For quick Q&A and basic interactions
export const getFastReply = async (message: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-lite-latest',
      contents: message,
      config: {
        systemInstruction: "You are the Healthy.hub Fast Assistant. Give extremely brief, clinical, and helpful answers. Under 30 words."
      }
    });
    return response.text;
  } catch (error) {
    return handleGenAIError(error);
  }
};

export const analyzeFoodImage = async (base64Image: string, userHint?: string): Promise<FoodAnalysis> => {
  try {
    let promptText = "Analyze this meal. Identify ingredients, provide nutrition JSON, and suggest a healthier alternative.";
    if (userHint) promptText = `Analyze the image strictly as "${userHint}", calculate accurate macros, and provide nutrition JSON.`;
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: [{ inlineData: { mimeType: 'image/jpeg', data: base64Image.split(',')[1] } }, { text: promptText }] },
      config: { responseMimeType: "application/json", responseSchema: foodResponseSchema }
    });
    if (response.text) return JSON.parse(response.text) as FoodAnalysis;
    throw new Error("AI returned empty analysis.");
  } catch (error) { return handleGenAIError(error); }
};

export const analyzeFoodText = async (query: string): Promise<FoodAnalysis> => {
  try {
    // Using Flash Lite for text-only estimation to ensure low latency
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-lite-latest',
      contents: `Estimate nutrition for: ${query}.`,
      config: { responseMimeType: "application/json", responseSchema: foodResponseSchema }
    });
    if (response.text) return JSON.parse(response.text) as FoodAnalysis;
    throw new Error("Empty AI response");
  } catch (error) { return handleGenAIError(error); }
};

export const generateWorkoutRoutine = async (level: string, goal: string, equipment: string, metrics: UserMetrics): Promise<WorkoutPlan> => {
  try {
    const prompt = `Create a high-intensity fitness routine. Stats: H ${metrics.height}, W ${metrics.weight}. Level: ${level}. Goal: ${goal}. Equipment: ${equipment}.`;
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: { 
        responseMimeType: "application/json", 
        responseSchema: workoutResponseSchema,
        thinkingConfig: { thinkingBudget: 32768 } // High-quality reasoning for routines
      }
    });
    if (response.text) return { id: Date.now().toString(), timestamp: Date.now(), ...JSON.parse(response.text) } as WorkoutPlan;
    throw new Error("Empty AI response");
  } catch (error) { return handleGenAIError(error); }
};

export const parseCheckInResponse = async (userText: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-lite-latest',
      contents: `Extract metrics from daily check-in: "${userText}"`,
      config: { responseMimeType: "application/json", responseSchema: checkInExtractionSchema }
    });
    return response.text ? JSON.parse(response.text) : null;
  } catch (error) { return null; }
};

export type CoachIntensity = 'Luxury' | 'Standard' | 'Ruthless';

export const getCoachChatStream = async (
  message: string, 
  history: Content[], 
  metrics: UserMetrics, 
  activity: ActivityData,
  intensity: CoachIntensity = 'Standard',
  isThinkingMode: boolean = true
) => {

  let personaInstruction = "";
  switch (intensity) {
    case 'Luxury':
      personaInstruction = "PERSONA: 'Wellness Concierge'. Sophisticated, polite, encouraging. Focus on refinement and elite wellness.";
      break;
    case 'Ruthless':
      personaInstruction = "PERSONA: 'Iron Sergeant'. Aggressive, demanding, zero-tolerance. Focus on discipline and results.";
      break;
    default:
      personaInstruction = "PERSONA: 'Elite Professional'. Direct, clinical, results-driven. Focus on optimization.";
      break;
  }

  const systemInstruction = `You are the Healthy.hub Elite AI Coach. Adhere strictly to: ${personaInstruction}.
  User Stats: ${metrics.height}cm / ${metrics.weight}kg.
  Today: ${activity.steps} steps.
  PROTOCOL: If the user asks for changes, include SYNC_PROTOCOL: {"calories": 1800, "steps": 12000, "plan_name": "Phase 1"}`;

  const model = isThinkingMode ? 'gemini-3-pro-preview' : 'gemini-2.5-flash-lite-latest';
  const config: any = { 
    systemInstruction, 
    temperature: 0.7 
  };

  if (isThinkingMode) {
    config.thinkingConfig = { thinkingBudget: 32768 };
  }

  const chat = ai.chats.create({ model, config, history });

  try {
    return await chat.sendMessageStream({ message });
  } catch (error) { return handleGenAIError(error); }
};

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Send, User, Bot, Sparkles, Loader2, Dumbbell, Trash2, Zap, Save, CheckCircle, Settings2, Bookmark, Brain, ZapOff, Info } from 'lucide-react';
