  // Persona & Intelligence State
  const [intensity, setIntensity] = useState<CoachIntensity>('Standard');
  const [thinkingMode, setThinkingMode] = useLocalStorage<boolean>('ai_thinking_mode', true);
  const [showSettings, setShowSettings] = useState(false);

  // Generator State
  const [savedWorkouts, setSavedWorkouts] = useLocalStorage<WorkoutPlan[]>('saved_workouts', []);
  const [genLoading, setGenLoading] = useState(false);
  const [genResult, setGenResult] = useState<WorkoutPlan | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const [fitnessLevel, setFitnessLevel] = useState('Intermediate');
  const [goal, setGoal] = useState('Muscle Gain');
  const [equipment, setEquipment] = useState('Dumbbells Only');

  const [activeCheckIn, setActiveCheckIn] = useState(!!checkInContext);

  useEffect(() => {
    const initChat = async () => {
       const { data: { user } } = await supabase.auth.getUser();
       if (!user) return;
       setUserId(user.id);
       try {
           const history = await fetchChatHistory(user.id);
           setMessages(history.map(h => ({
               id: h.id, 
               role: h.is_user_message ? 'user' : 'model', 
               text: h.message, 
               timestamp: new Date(h.created_at).getTime(),
               plan_data: h.plan_data
           })));
       } finally { setIsLoading(false); }
    };
    initChat();
  }, []);

  useEffect(() => {
    if (checkInContext && !isLoading && messages.length === 0 && userId) {
        setMessages([{ id: 'init', role: 'model', text: checkInContext, timestamp: Date.now() }]);
        setActiveCheckIn(true);
        saveChatMessage(userId, checkInContext, false);
    }
  }, [checkInContext, isLoading, messages.length, userId]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages, isTyping, isThinking]);

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isTyping || !userId) return;

    const userText = input;
    setMessages(prev => [...prev, { id: Date.now().toString(), role: 'user', text: userText, timestamp: Date.now() }]);
    setInput('');
    setIsTyping(true);
    if (thinkingMode) setIsThinking(true);

    saveChatMessage(userId, userText, true).catch(console.error);

    try {
      if (activeCheckIn) {
          const parsed = await parseCheckInResponse(userText);
          if (parsed) {
              if (onUpdateMetrics && (parsed.newWeight || parsed.newHeight)) {
                  onUpdateMetrics({ ...metrics, weight: parsed.newWeight ?? metrics.weight, height: parsed.newHeight ?? metrics.height });
              }
              const reply = parsed.replyMessage || "Status synchronized.";
              setMessages(prev => [...prev, { id: 'reply', role: 'model', text: reply, timestamp: Date.now() }]);
              await saveChatMessage(userId, reply, false);
              setActiveCheckIn(false);
              setIsTyping(false);
              setIsThinking(false);
              return;
          }
      }

      const history: Content[] = messages.map(m => ({ role: m.role, parts: [{ text: m.text }] }));
      const stream = await getCoachChatStream(userText, history, metrics, activity, intensity, thinkingMode);
      const coachId = Date.now().toString();
      let coachText = '';

      setMessages(prev => [...prev, { id: coachId, role: 'model', text: '', timestamp: Date.now() }]);
      setIsThinking(false); // Switch from thinking state to streaming state

      for await (const chunk of stream) {
        coachText += chunk.text || '';
        setMessages(prev => prev.map(m => m.id === coachId ? { ...m, text: coachText } : m));
      }

      const protocolMatch = coachText.match(/SYNC_PROTOCOL:\s*(\{.*\})/);
      let planData = null;
      if (protocolMatch) {
          try {
              planData = JSON.parse(protocolMatch[1]);
              setIsSyncing(true);
              await updateUserTargets(userId, planData);
              if (onUpdateTargets) onUpdateTargets(planData.calories, planData.steps, planData.plan_name);
              setMessages(prev => prev.map(m => m.id === coachId ? { ...m, plan_data: planData } : m));
              setTimeout(() => setIsSyncing(false), 2000);
          } catch (e) { console.error("Sync Error:", e); }
      }

      await saveChatMessage(userId, coachText, false, planData);

    } catch (error: any) {
      setErrorMsg(error.message || "Protocol Interrupted");
    } finally { 
      setIsTyping(false); 
      setIsThinking(false);
    }
  };

  const handleGenerateWorkout = async () => {
    setGenLoading(true);
    setErrorMsg(null);
    try {
      const result = await generateWorkoutRoutine(fitnessLevel, goal, equipment, metrics);
      setGenResult(result);
    } catch (e: any) {
      setErrorMsg("Failed to generate workout. Please try again.");
    } finally {
      setGenLoading(false);
    }
  };

  return (
    <div className="h-full w-full flex flex-col bg-[#050505] relative">
      <AnimatePresence>
         {isSyncing && (
            <motion.div initial={{ y: -50 }} animate={{ y: 20 }} exit={{ y: -50 }} className="absolute top-24 left-1/2 -translate-x-1/2 z-[60] bg-luxury-neon px-6 py-2 rounded-full text-black font-black text-[10px] uppercase tracking-widest shadow-2xl flex items-center gap-2">
               <Loader2 size={12} className="animate-spin" /> Syncing AI Targets...
            </motion.div>
         )}
      </AnimatePresence>

      <div className="p-6 pt-12 flex items-center justify-between border-b border-white/5 z-10 bg-black/40 backdrop-blur-md shrink-0">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 rounded-full bg-luxury-neon/10 flex items-center justify-center border border-luxury-neon/30 relative">
            {thinkingMode ? <Brain size={24} className="text-luxury-neon" /> : <Zap size={24} className="text-luxury-neon" />}
            {isThinking && (
              <div className="absolute inset-0 border-2 border-luxury-neon rounded-full animate-ping opacity-20"></div>
            )}
          </div>
          <div>
            <h1 className="text-xl font-bold text-white">Coach Gemini</h1>
            <div className="flex items-center gap-2">
              <span className={`text-[10px] uppercase font-black tracking-widest ${thinkingMode ? 'text-luxury-neon' : 'text-blue-400'}`}>
                 {thinkingMode ? 'Deep Intelligence' : 'Ultra Fast'}
              </span>
            </div>
          </div>
        </div>

        <div className="flex gap-2">
           <button 
             onClick={() => setShowSettings(!showSettings)} 
             className={`p-3 rounded-full border transition-all ${showSettings ? 'bg-luxury-neon text-black border-luxury-neon shadow-[0_0_15px_rgba(206,242,69,0.3)]' : 'bg-white/5 text-gray-400 border-white/10'}`}
           >
              <Settings2 size={18} />
           </button>
           <button 
             onClick={() => setMode(mode === 'chat' ? 'generator' : 'chat')} 
             className={`p-3 rounded-full border transition-all ${mode === 'generator' ? 'bg-luxury-neon text-black border-luxury-neon shadow-[0_0_15px_rgba(206,242,69,0.3)]' : 'bg-white/5 text-gray-400 border-white/10'}`}
           >
              <Zap size={18} />
           </button>
        </div>
      </div>

      <AnimatePresence>
        {showSettings && (
          <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} className="bg-black/80 backdrop-blur-xl border-b border-white/10 overflow-hidden">
            <div className="p-6 space-y-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-xs font-black text-white uppercase tracking-widest mb-1">Hyper-Intelligence</p>
