  Goal: Provide ultra-precise, scientific fitness advice. 
  If user asks for a plan change, include: SYNC_PROTOCOL: {"calories": 1800, "steps": 12000, "plan_name": "Phase 1"}`;

  const model = isThinkingMode ? 'gemini-3-pro-preview' : 'gemini-flash-lite-latest';

  const config: any = { 
    systemInstruction, 
    temperature: 0.7 
  };

  if (isThinkingMode) {
    // Max thinking budget for Gemini 3 Pro
    config.thinkingConfig = { thinkingBudget: 32768 };
  }

  const chat = ai.chats.create({ model, config, history });

  try {
