import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Send, User, Bot, Sparkles, Loader2, Dumbbell, Trash2, Zap, Save, CheckCircle, Settings2, Brain, ZapOff, Info, ArrowRight } from 'lucide-react';
import { getCoachChatStream, generateWorkoutRoutine } from '../services/geminiService';
import { fetchChatHistory, saveChatMessage, supabase, updateUserTargets } from '../services/supabase';
import { ChatMessage, UserMetrics, ActivityData, WorkoutPlan } from '../types';
import { Content } from '@google/genai';
import useLocalStorage from '../hooks/useLocalStorage';

interface ChatBotProps {
  metrics: UserMetrics;
  activity: ActivityData;
  onUpdateTargets?: (calories: number, steps: number, planName: string) => void;
}

const ChatBot: React.FC<ChatBotProps> = ({ metrics, activity, onUpdateTargets }) => {
  const [mode, setMode] = useState<'chat' | 'generator'>('chat');
  const [messages, setMessages] = useState<(ChatMessage & { plan_data?: any })[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isThinking, setIsThinking] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const scrollRef = useRef<HTMLDivElement>(null);
  const [userId, setUserId] = useState<string | null>(null);

  const [thinkingMode, setThinkingMode] = useLocalStorage<boolean>('ai_thinking_mode', true);
  const [showSettings, setShowSettings] = useState(false);

  useEffect(() => {
    const initChat = async () => {
       const { data: { user } } = await supabase.auth.getUser();
       if (!user) return;
       setUserId(user.id);
       try {
           const history = await fetchChatHistory(user.id);
           setMessages(history.map(h => ({
               id: h.id, 
               role: h.is_user_message ? 'user' : 'model', 
               text: h.message, 
               timestamp: new Date(h.created_at).getTime(),
               plan_data: h.plan_data
           })));
       } finally { setIsLoading(false); }
    };
    initChat();
  }, []);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages, isTyping, isThinking]);

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isTyping || !userId) return;

    const userText = input;
    setMessages(prev => [...prev, { id: Date.now().toString(), role: 'user', text: userText, timestamp: Date.now() }]);
    setInput('');
    setIsTyping(true);
    if (thinkingMode) setIsThinking(true);

    saveChatMessage(userId, userText, true).catch(console.error);

    try {
      const history: Content[] = messages.map(m => ({ role: m.role, parts: [{ text: m.text }] }));
      const stream = await getCoachChatStream(userText, history, metrics, activity, thinkingMode);
      const coachId = Date.now().toString();
      let coachText = '';

      setMessages(prev => [...prev, { id: coachId, role: 'model', text: '', timestamp: Date.now() }]);
      setIsThinking(false);

      for await (const chunk of stream) {
        coachText += chunk.text || '';
        setMessages(prev => prev.map(m => m.id === coachId ? { ...m, text: coachText } : m));
      }

      const protocolMatch = coachText.match(/SYNC_PROTOCOL:\s*(\{.*\})/);
      let planData = null;
      if (protocolMatch) {
          try {
              planData = JSON.parse(protocolMatch[1]);
              await updateUserTargets(userId, planData);
              if (onUpdateTargets) onUpdateTargets(planData.calories, planData.steps, planData.plan_name);
              setMessages(prev => prev.map(m => m.id === coachId ? { ...m, plan_data: planData } : m));
          } catch (e) { console.error("Sync Protocol Error", e); }
      }

      await saveChatMessage(userId, coachText, false, planData);

    } catch (error: any) {
      setMessages(prev => [...prev, { id: 'err', role: 'model', text: "Protocol interrupted. Please try again.", timestamp: Date.now() }]);
    } finally { 
      setIsTyping(false); 
      setIsThinking(false);
    }
  };

  return (
    <div className="h-full w-full flex flex-col bg-[#050505] relative font-sans">
      {/* Dynamic Header */}
      <div className="p-6 pt-12 flex items-center justify-between border-b border-white/5 z-10 bg-black/40 backdrop-blur-md">
        <div className="flex items-center gap-4">
          <div className={`w-12 h-12 rounded-full flex items-center justify-center border transition-all duration-700 ${thinkingMode ? 'border-luxury-neon/50 bg-luxury-neon/5 shadow-[0_0_20px_rgba(206,242,69,0.2)]' : 'border-white/10 bg-white/5'}`}>
            {thinkingMode ? <Brain size={24} className="text-luxury-neon" /> : <Zap size={24} className="text-gray-400" />}
          </div>
          <div>
            <h1 className="text-xl font-black text-white tracking-tight uppercase">AI Coach</h1>
            <div className="flex items-center gap-2">
              <span className={`text-[9px] uppercase font-black tracking-[0.2em] ${thinkingMode ? 'text-luxury-neon' : 'text-gray-500'}`}>
                 {thinkingMode ? 'Hyper-Intelligence Active' : 'Low Latency Protocol'}
              </span>
            </div>
          </div>
        </div>

        <button 
          onClick={() => setShowSettings(!showSettings)} 
          className={`p-3 rounded-full border transition-all ${showSettings ? 'bg-luxury-neon text-black border-luxury-neon' : 'bg-white/5 text-gray-500 border-white/10'}`}
        >
          <Settings2 size={18} />
        </button>
      </div>

      <AnimatePresence>
        {showSettings && (
          <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} className="bg-white/[0.02] border-b border-white/10 overflow-hidden">
            <div className="p-6 space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-[10px] font-black text-white uppercase tracking-widest mb-1">Thinking Mode</p>
                  <p className="text-[8px] text-gray-500 uppercase tracking-widest">Utilize Gemini 3 Pro (32K Budget)</p>
                </div>
                <button 
                  onClick={() => setThinkingMode(!thinkingMode)} 
                  className={`w-12 h-6 rounded-full relative transition-all duration-300 ${thinkingMode ? 'bg-luxury-neon' : 'bg-white/10'}`}
                >
                  <motion.div 
                    animate={{ x: thinkingMode ? 26 : 4 }}
                    className={`absolute top-1 w-4 h-4 rounded-full ${thinkingMode ? 'bg-black' : 'bg-gray-400'}`}
                  />
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Chat Area */}
      <div className="flex-1 overflow-hidden relative flex flex-col">
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 no-scrollbar">
          {messages.map((msg) => (
            <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                {msg.plan_data && (
                  <div className="mb-2 px-3 py-1 bg-luxury-neon/10 border border-luxury-neon/20 rounded-full text-[8px] font-black text-luxury-neon uppercase tracking-widest">
                    Protocol Synced: {msg.plan_data.plan_name}
                  </div>
                )}
                <div className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed ${msg.role === 'user' ? 'bg-luxury-neon text-black font-bold' : 'bg-white/5 text-white border border-white/5'}`}>
                    {msg.text.replace(/SYNC_PROTOCOL:\s*\{.*\}/, '').trim()}
                </div>
            </div>
          ))}

          {isThinking && (
            <div className="flex flex-col items-start">
              <div className="bg-white/5 border border-white/5 p-4 rounded-2xl flex items-center gap-3">
                <div className="flex gap-1">
                  {[0, 1, 2].map(i => (
                    <motion.div key={i} animate={{ scale: [1, 1.5, 1], opacity: [0.3, 1, 0.3] }} transition={{ repeat: Infinity, delay: i * 0.2, duration: 1 }} className="w-1.5 h-1.5 bg-luxury-neon rounded-full" />
                  ))}
                </div>
                <span className="text-[9px] font-black text-gray-500 uppercase tracking-widest">Processing thinking budget...</span>
              </div>
            </div>
          )}
        </div>

        {/* Input Bar */}
        <div className="p-6 pb-12 bg-black border-t border-white/10">
          <form onSubmit={handleSend} className="flex items-center gap-3">
            <input 
              type="text" 
              value={input} 
              onChange={(e) => setInput(e.target.value)} 
              placeholder={thinkingMode ? "Ask for complex analysis..." : "Quick inquiry..."} 
              className="flex-1 bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-sm text-white placeholder-gray-700 outline-none focus:border-luxury-neon/40 transition-all" 
            />
            <button type="submit" disabled={isTyping || !input.trim()} className="w-14 h-14 rounded-2xl bg-luxury-neon text-black flex items-center justify-center disabled:opacity-30 active:scale-95 transition-all shadow-[0_0_20px_rgba(206,242,69,0.3)]">
              {isTyping ? <Loader2 className="animate-spin" size={20} /> : <Send size={20} />}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default ChatBot;

