  const [fullProfile, setFullProfile] = useState<UserProfile | null>(null);

  const [thinkingMode, setThinkingMode] = useLocalStorage<boolean>('ai_thinking_mode', true);
  const [showSettings, setShowSettings] = useState(false);

  // Initial Sync: Load user and profile once
  useEffect(() => {
    const initChat = async () => {
       const { data: { user } } = await supabase.auth.getUser();
       if (!user) return;
       setUserId(user.id);

       try {
           // 1. Fetch real height, weight, goals from Supabase profiles table
           const { data: profileData } = await supabase
             .from('profiles')
             .select('*')
             .eq('id', user.id)
             .maybeSingle();

           if (profileData) {
              setFullProfile({
                id: profileData.id,
                name: profileData.name || 'Elite Member',
