                  calorieGoal: profileData.daily_calorie_goal || 2000,
                  distanceGoal: 5.0
                }
              });
           }

           // 2. Fetch history
           const history = await fetchChatHistory(user.id);
           setMessages(history.map(h => ({
               id: h.id, 
               role: h.is_user_message ? 'user' : 'model', 
               text: h.message, 
               timestamp: new Date(h.created_at).getTime(),
               plan_data: h.plan_data
           })));
       } finally { setIsLoading(false); }
    };
    initChat();
  }, [metrics]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages, isTyping, isThinking]);

  /**
   * REFACTORED HANDLER:
   * 1. Updates UI instantly.
   * 2. Injects real Supabase metrics.
   * 3. Appends last 10 messages for memory.
   * 4. Robust error handling.
   */
  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isTyping || !userId || !fullProfile) return;

    const userText = input;

    // 1. UI UPDATES IMMEDIATELY
    const userMsg: ChatMessage = { 
      id: Date.now().toString(), 
      role: 'user', 
      text: userText, 
      timestamp: Date.now() 
    };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);
    if (thinkingMode) setIsThinking(true);

