        .slice(-10) // Take only last 10 for optimized token usage
        .map(m => ({ 
          role: m.role, 
          parts: [{ text: m.text }] 
        }));

      // 3. GENERATE AI RESPONSE WITH REAL CONTEXT
      const stream = await getCoachChatStream(
        userText, 
        historyContext, 
        fullProfile, 
        activity, 
        thinkingMode
      );

      const coachId = (Date.now() + 1).toString();
      let coachText = '';

      // Initialize model message in UI
      setMessages(prev => [...prev, { id: coachId, role: 'model', text: '', timestamp: Date.now() }]);
      setIsThinking(false); // Transition from thinking animation to streaming text

      for await (const chunk of stream) {
        coachText += chunk.text || '';
        setMessages(prev => prev.map(m => m.id === coachId ? { ...m, text: coachText } : m));
      }

      // 4. PROTOCOL SYNC (If AI proposed a plan change)
      const protocolMatch = coachText.match(/SYNC_PROTOCOL:\s*(\{.*\})/);
      let planData = null;
      if (protocolMatch) {
          try {
              planData = JSON.parse(protocolMatch[1]);
              await updateUserTargets(userId, planData);
              if (onUpdateTargets) onUpdateTargets(planData.calories, planData.steps, planData.plan_name);
              setMessages(prev => prev.map(m => m.id === coachId ? { ...m, plan_data: planData } : m));
          } catch (e) { console.error("Protocol Sync Failure:", e); }
      }

      // Final save to database
      await saveChatMessage(userId, coachText, false, planData);

    } catch (error: any) {
      console.error("Coach Stream Failure:", error);
      const errorMsg = "Service Protocol Interrupted. The elite network is stabilizing. Please try again in a moment.";
      setMessages(prev => [...prev, { 
        id: 'err-' + Date.now(), 
        role: 'model', 
        text: errorMsg, 
        timestamp: Date.now() 
      }]);
    } finally { 
      setIsTyping(false); 
      setIsThinking(false);
    }
