import { GoogleGenAI, Type, Content } from "@google/genai";
import { FoodAnalysis, UserMetrics, ActivityData, WorkoutPlan, UserProfile } from "../types";

// Initialize the Google GenAI client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const foodResponseSchema = {
  type: Type.OBJECT,
  properties: {
    name: { type: Type.STRING, description: "Name of the food item" },
    macros: {
      type: Type.OBJECT,
      properties: {
        calories: { type: Type.NUMBER },
        protein: { type: Type.NUMBER },
        fat: { type: Type.NUMBER },
        carbs: { type: Type.NUMBER },
      },
      required: ["calories", "protein", "fat", "carbs"]
    },
    healthScore: { type: Type.NUMBER, description: "Score from 0-100" },
    verdict: { type: Type.STRING, enum: ["Excellent", "Good", "Fair", "Avoid"] },
    advice: { type: Type.STRING, description: "Short nutritional tip" },
    alternatives: { type: Type.STRING, description: "A healthier alternative" },
    colorCode: { type: Type.STRING, enum: ["green", "yellow", "red"] },
  },
  required: ["name", "macros", "healthScore", "verdict", "advice", "alternatives", "colorCode"]
};

const workoutResponseSchema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING, description: "Catchy name for the workout" },
    difficulty: { type: Type.STRING },
    duration: { type: Type.STRING, description: "Estimated time" },
    exercises: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          sets: { type: Type.STRING },
          reps: { type: Type.STRING },
          notes: { type: Type.STRING }
        },
        required: ["name", "sets", "reps", "notes"]
      }
    }
  },
  required: ["title", "difficulty", "duration", "exercises"]
};

const handleGenAIError = (error: any): never => {
  console.error("Gemini API Error:", error);
  throw new Error(error.message || "AI Protocol Interrupted.");
};

export const getFastHealthTip = async (userStats: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-flash-lite-latest',
      contents: `Give a 1-sentence luxury fitness tip for someone with these stats: ${userStats}. Keep it elite.`,
    });
    return response.text || "Stay elite.";
  } catch (error) {
    return "Optimizing performance...";
  }
};

/**
 * REFACTORED: Dynamic System Instruction based on real metrics.
 */
export const getCoachChatStream = async (
  message: string, 
  history: Content[], 
  profile: any, // Raw profile from DB
  activity: ActivityData,
  isThinkingMode: boolean = true
) => {
  const height = profile.height || 175;
  const weight = profile.weight || 70;
  const metrics = profile.metrics || {};
  const age = metrics.age || 25;
  const goal = metrics.fitnessGoal || 'Maintenance';
  const activityLevel = metrics.activityLevel || 'Moderately Active';

  // Specific System Instruction requested by user
  const systemInstruction = `You are an elite fitness coach for Healthy.hub. 
  The user is ${height}cm tall, weighs ${weight}kg, is ${age} years old, and their goal is ${goal}. 
  They are ${activityLevel}. 
  Today they have taken ${activity.steps} steps and burned ${Math.floor(activity.calories)} calories.
  Answer their question based on these real stats. Use a sophisticated, clinical, and result-oriented tone.

  If proposing a goal update, use: SYNC_PROTOCOL: {"calories": [num], "steps": [num], "plan_name": "[string]"}`;

  const model = isThinkingMode ? 'gemini-3-pro-preview' : 'gemini-flash-lite-latest';

  const config: any = { 
    systemInstruction, 
    temperature: 0.7 
  };

  if (isThinkingMode) {
    config.thinkingConfig = { thinkingBudget: 32768 };
  }

  const chat = ai.chats.create({ model, config, history });

  try {
    return await chat.sendMessageStream({ message });
  } catch (error) { 
    return handleGenAIError(error); 
  }
};

export const analyzeFoodImage = async (base64Image: string, hint?: string): Promise<FoodAnalysis> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { 
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: base64Image.split(',')[1] } }, 
          { text: `Analyze this meal. ${hint ? `Context from user: ${hint}. ` : ""}Provide nutritional breakdown in JSON.` }
        ] 
      },
      config: { 
        responseMimeType: "application/json", 
        responseSchema: foodResponseSchema 
      }
    });
    if (response.text) return JSON.parse(response.text) as FoodAnalysis;
    throw new Error("Analysis failed.");
  } catch (error) { return handleGenAIError(error); }
};

export const analyzeFoodText = async (text: string): Promise<FoodAnalysis> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze this food description: ${text}. Provide nutritional breakdown in JSON.`,
      config: { 
        responseMimeType: "application/json", 
        responseSchema: foodResponseSchema 
      }
    });
    if (response.text) return JSON.parse(response.text) as FoodAnalysis;
    throw new Error("Analysis failed.");
  } catch (error) { return handleGenAIError(error); }
};

export const generateWorkoutRoutine = async (level: string, goal: string, equipment: string, metrics: UserMetrics): Promise<WorkoutPlan> => {
  try {
    const prompt = `Create an elite workout. User: H${metrics.height}cm W${metrics.weight}kg. Level: ${level}. Goal: ${goal}. Equipment: ${equipment}.`;
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: { 
        responseMimeType: "application/json", 
        responseSchema: workoutResponseSchema,
        thinkingConfig: { thinkingBudget: 32768 } 
      }
    });
    if (response.text) return { id: Date.now().toString(), timestamp: Date.now(), ...JSON.parse(response.text) } as WorkoutPlan;
    throw new Error("Generation failed.");
  } catch (error) { return handleGenAIError(error); }
};

export interface MapInsight {
  text: string;
  sources: { uri: string; title: string }[];
}

export const getCalibrationInsight = async (lat: number, lng: number): Promise<MapInsight> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Provide an elite health and location insight for someone at coordinates ${lat}, ${lng}. Mention any nearby high-performance landmarks if relevant.`,
      config: {
        tools: [{ googleSearch: {} }]
      }
    });

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        uri: chunk.web?.uri || "",
        title: chunk.web?.title || "Reference"
      }))
      .filter((s: any) => s.uri) || [];

    return {
      text: response.text || "Optimize your stride in this environment.",
      sources: sources
    };
  } catch (error) {
    return { text: "Protocol active. Optimize your performance.", sources: [] };
  }
};

