export const syncDailyActivity = async (userId: string, steps: number, calories: number, stepGoal: number, distanceKm: number = 0) => {
  if (isGuest(userId)) return;

  const todayKey = getLocalTodayKey();
  const isTargetMet = steps >= stepGoal;

  try {
    const { error } = await supabase.from('daily_activity').upsert({ 
      user_id: userId, 
      activity_date: todayKey, 
      steps: steps, 
      calories_burned: calories, 
      distance_km: distanceKm,
      is_target_met: isTargetMet,
      updated_at: new Date().toISOString()
    }, { 
      onConflict: 'user_id, activity_date' 
    });
    if (error) throw error;
  } catch (e) {
    console.error(`❌ ERROR SAVING:`, e);
  }
};

// --- FETCH FUNCTION (Enhanced with PGRST205 Handling) ---
export const fetchFullUserDashboard = async (userId: string) => {
  if (isGuest(userId)) {
    return {
      profile: {
        id: userId,
        name: 'Guest Elite',
        email: 'guest@healthyhub.com',
        avatarUrl: DEFAULT_AVATAR,
        goals: { stepGoal: 10000, calorieGoal: 2000, distanceGoal: 5.0 },
        metrics: {}
      },
      todayActivity: null,
      foodLogs: [],
      chatHistory: []
    };
  }

  try {
    const todayKey = getLocalTodayKey();

    // 1. Fetch Profile
    const { data: profileData, error: profileError } = await supabase.from('profiles').select('*').eq('id', userId).maybeSingle();

    // Check specifically for PGRST205 (Missing Table)
    if (profileError && (profileError as any).code === 'PGRST205') {
       console.warn("⚠️ Supabase: Profiles table missing. Using defaults.");
       return _getFallbackDashboard(userId);
    }

    if (!profileData) return null;

    // 2. Fetch Daily Activity
    const { data: activityData, error: activityError } = await supabase
      .from('daily_activity')
      .select('*')
      .eq('user_id', userId)
      .eq('activity_date', todayKey)
      .maybeSingle();

    // Check for PGRST205 in activity fetch
    if (activityError && (activityError as any).code === 'PGRST205') {
       console.warn("⚠️ Supabase: Daily Activity table missing. Using zero-state.");
    }

    // 3. Parallel Fetch for logs/history
    const [foodRes, chatRes] = await Promise.all([
      supabase.from('food_logs').select('*').eq('user_id', userId).order('created_at', { ascending: false }).limit(20),
      supabase.from('chat_history').select('*').eq('user_id', userId).order('created_at', { ascending: true }).limit(50)
    ]);

    return {
      profile: mapProfileToAppFormat(profileData),
      todayActivity: activityData || null,
      foodLogs: foodRes.data as FoodLogDB[] || [],
      chatHistory: chatRes.data as ChatHistoryDB[] || []
    };
  } catch (e) {
    console.error("Fetch Logic Error (Handled):", e);
    return _getFallbackDashboard(userId);
  }
};

