import React, { useState, useEffect } from 'react';
import { AnimatePresence } from 'framer-motion';
import { 
  onAuthStateChanged,
  User,
  fetchFullUserDashboard,
  syncDailyActivity
} from './services/supabase';

import Navigation from './components/Navigation';
import Dashboard from './components/Dashboard';
import FoodLens from './components/FoodLens';
import BMIHub from './components/BMIHub';
import MapTrackingScreen from './components/MapTrackingScreen';
import ChatBot from './components/ChatBot';
import ProfileScreen from './components/ProfileScreen';
import OnboardingScreen from './components/OnboardingScreen'; 
import WorkoutLab from './components/WorkoutLab';
import Auth from './components/Auth';
import { ViewState, ActivityData, FoodHistoryItem, UserMetrics } from './types';
import useLocalStorage from './hooks/useLocalStorage';
import usePedometer from './hooks/usePedometer';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [userProfile, setUserProfile] = useState<any>(null);
  const [isAuthChecking, setIsAuthChecking] = useState(true); 
  const [isProfileChecking, setIsProfileChecking] = useState(false);

  // --- THE LOADING LOCK (Safety Gate) ---
  const [isInitialLoadComplete, setIsInitialLoadComplete] = useState(false);

  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);
  const { isTracking, toggleTracking, liveSteps, resetLiveSteps } = usePedometer();

  const [activityData, setActivityData] = useState<ActivityData>({
    steps: 0, calories: 0, distance: 0, stepGoal: 10000, calorieGoal: 2000, distanceGoal: 5.0, history: []
  });

  const [bmiMetrics, setBmiMetrics] = useLocalStorage<UserMetrics>('bmi_metrics', { height: 175, weight: 70 });
  const [foodHistory, setFoodHistory] = useLocalStorage<FoodHistoryItem[]>('food_history', []);
  const [adaptiveGoalsEnabled, setAdaptiveGoalsEnabled] = useLocalStorage<boolean>('adaptive_goals_enabled', true);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(async (user) => {
      setIsInitialLoadComplete(false);

      if (user) {
        setCurrentUser(user);
        setIsProfileChecking(true);

        try {
          // fetchFullUserDashboard is now robust against PGRST205 errors
          const dashboardData = await fetchFullUserDashboard(user.id);

          if (dashboardData) {
              if (dashboardData.profile) setUserProfile(dashboardData.profile);

              setActivityData(prev => ({
                ...prev,
                steps: dashboardData.todayActivity?.steps || 0,
                calories: dashboardData.todayActivity?.calories_burned || 0,
                stepGoal: dashboardData.profile?.goals?.stepGoal || prev.stepGoal,
                calorieGoal: dashboardData.profile?.goals?.calorieGoal || prev.calorieGoal
              }));
          }
        } catch (e) {
          console.error("Critical Profile Load Failure:", e);
        } finally {
          // Safety: Release the loading lock no matter what happens
          setIsInitialLoadComplete(true);
          setIsProfileChecking(false);
        }
      } else { 
        setCurrentUser(null); 
        setUserProfile(null);
        setIsInitialLoadComplete(false);
      }
      setIsAuthChecking(false);
    });
    return () => { if (unsubscribe) unsubscribe(); };
  }, []);

  useEffect(() => {
    if (!currentUser || !isInitialLoadComplete) return;

    if (liveSteps > 0) {
       setActivityData(prev => {
          const newSteps = prev.steps + liveSteps;
          const newCals = prev.calories + (liveSteps * 0.04);
          syncDailyActivity(currentUser.id, newSteps, Math.floor(newCals), prev.stepGoal);
          return { ...prev, steps: newSteps, calories: newCals };
       });
       resetLiveSteps();
    }
  }, [liveSteps, currentUser, isInitialLoadComplete, resetLiveSteps]);

  const handleUpdateGoals = (newGoals: Partial<ActivityData>) => setActivityData(prev => ({ ...prev, ...newGoals }));

  if (isAuthChecking) return <div className="h-screen bg-black flex items-center justify-center text-luxury-neon animate-pulse text-[10px] uppercase tracking-[0.3em]">Initialising Ecosystem...</div>;
  if (!currentUser) return <Auth onLoginSuccess={() => {}} />;
  if (isProfileChecking) return <div className="h-screen bg-black flex items-center justify-center text-gray-400 text-[10px] uppercase tracking-[0.3em]">Synchronizing Records...</div>;

  if (!userProfile) {
     return <OnboardingScreen user={currentUser} onComplete={(p) => { setUserProfile(p); setCurrentView(ViewState.DASHBOARD); }} />;
  }

  return (
    <div className="flex flex-col h-[100dvh] bg-black text-white relative overflow-hidden font-sans">
      <main className="flex-1 relative w-full overflow-hidden">
        <AnimatePresence mode="wait">
          {currentView === ViewState.DASHBOARD && (
            <Dashboard 
              key="dash" 
              data={activityData} 
              onUpdateGoals={handleUpdateGoals} 
              isTracking={isTracking} 
              onToggleTracking={toggleTracking} 
              foodHistory={foodHistory}
              adaptiveGoalsEnabled={adaptiveGoalsEnabled}
              onToggleAdaptiveGoals={setAdaptiveGoalsEnabled}
            />
          )}
          {currentView === ViewState.CHAT && <ChatBot key="chat" metrics={bmiMetrics} activity={activityData} />}
          {currentView === ViewState.FOOD_LENS && <FoodLens key="lens" history={foodHistory} onAddToHistory={h => setFoodHistory([h, ...foodHistory])} />}
          {currentView === ViewState.BMI_HUB && <BMIHub key="bmi" />}
          {currentView === ViewState.MAP_TRACKER && <MapTrackingScreen key="map" userHeight={bmiMetrics.height} />}
          {currentView === ViewState.PROFILE && <ProfileScreen key="profile" onUpdateMetrics={setBmiMetrics} />}
          {currentView === ViewState.WORKOUT_LAB && <WorkoutLab key="lab" metrics={bmiMetrics} />}
        </AnimatePresence>
      </main>
      <Navigation currentView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

