/**
 * UPDATED: Injects real-time user profile data and activity metrics into the system instruction.
 * Handles conversational history for memory.
 */
export const getCoachChatStream = async (
  message: string, 
  history: Content[], 
  profile: any, 
  activity: ActivityData,
  isThinkingMode: boolean = true
) => {
  const height = profile.height || 175;
  const weight = profile.weight || 70;
  const metrics = profile.metrics || {};
  const age = metrics.age || 25;
  const goal = metrics.fitnessGoal || 'Maintenance';
  const activityLevel = metrics.activityLevel || 'Moderately Active';

  const systemInstruction = `You are the Healthy.hub Elite AI Coach. 
  Persona: Wellness Concierge. Sophisticated, clinical, result-oriented.

  CURRENT BIO-DATA:
  - Height: ${height}cm
  - Weight: ${weight}kg
  - Age: ${age}
  - Goal: ${goal}
  - Activity Level: ${activityLevel}

  TODAY'S PROGRESS:
  - Steps: ${activity.steps}
  - Calories Burned: ${Math.floor(activity.calories)}

  PROTOCOL: 
  Provide ultra-precise, scientific fitness advice based on the user's REAL bio-data provided above.
  Be encouraging but direct.
  If the user asks to modify their goals or start a new plan, you MUST include the sync token: 
  SYNC_PROTOCOL: {"calories": [new_goal], "steps": [new_goal], "plan_name": "[plan_description]"}

  History of the last 10 messages is provided. Maintain context.`;

  const model = isThinkingMode ? 'gemini-3-pro-preview' : 'gemini-flash-lite-latest';

  const config: any = { 
    systemInstruction, 
    temperature: 0.7 
  };

  if (isThinkingMode) {
    config.thinkingConfig = { thinkingBudget: 32768 };
  }

  // Gemini Chat Session with history
  const chat = ai.chats.create({ 
    model, 
    config, 
    history 
  });

  try {
    return await chat.sendMessageStream({ message });
  } catch (error) { 
    return handleGenAIError(error); 
  }
};

