export const generateWorkoutRoutine = async (
  level: string, 
  goal: string, 
  equipment: string, 
  duration: string,
  intensity: string,
  metrics: UserMetrics
): Promise<WorkoutPlan> => {
  try {
    const prompt = `Create an elite workout routine. 
    User Profile: Height ${metrics.height}cm, Weight ${metrics.weight}kg, Goal: ${goal}. 
    Preferences: 
    - Level: ${level}
    - Intensity: ${intensity}
    - Duration: ${duration}
    - Available Equipment: ${equipment}

    Provide a professional, structured workout with exercises, sets, reps, and notes in JSON.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: { 
        responseMimeType: "application/json", 
        responseSchema: workoutResponseSchema,
        thinkingConfig: { thinkingBudget: 32768 } 
      }
    });
    if (response.text) {
      const data = JSON.parse(response.text);
      return { 
        id: Date.now().toString(), 
        timestamp: Date.now(), 
        ...data,
        intensity,
        equipment
      } as WorkoutPlan;
    }
    throw new Error("Generation failed.");
  } catch (error) { return handleGenAIError(error); }
};

export interface MapInsight {
  text: string;
  sources: { uri: string; title: string }[];
}

export const getCalibrationInsight = async (lat: number, lng: number): Promise<MapInsight> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Provide an elite health and location insight for someone at coordinates ${lat}, ${lng}. Mention any nearby high-performance landmarks if relevant.`,
      config: {
        tools: [{ googleSearch: {} }]
      }
    });

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        uri: chunk.web?.uri || "",
        title: chunk.web?.title || "Reference"
      }))
      .filter((s: any) => s.uri) || [];

    return {
      text: response.text || "Optimize your stride in this environment.",
      sources: sources
    };
  } catch (error) {
    return { text: "Protocol active. Optimize your performance.", sources: [] };
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Send, Sparkles, Loader2, Brain, Zap, Settings2, Trash2, AlertCircle } from 'lucide-react';
import { getCoachChatStream } from '../services/geminiService';
import { fetchChatHistory, saveChatMessage, supabase, updateUserTargets, clearChatHistory } from '../services/supabase';
import { ChatMessage, UserMetrics, ActivityData, UserProfile } from '../types';
import { Content } from '@google/genai';
import useLocalStorage from '../hooks/useLocalStorage';

interface ChatBotProps {
  metrics: UserMetrics;
  activity: ActivityData;
  onUpdateTargets?: (calories: number, steps: number, planName: string) => void;
}

const ChatBot: React.FC<ChatBotProps> = ({ metrics, activity, onUpdateTargets }) => {
  const [messages, setMessages] = useState<(ChatMessage & { plan_data?: any })[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isThinking, setIsThinking] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const scrollRef = useRef<HTMLDivElement>(null);
  const [userId, setUserId] = useState<string | null>(null);

  const [thinkingMode, setThinkingMode] = useLocalStorage<boolean>('ai_thinking_mode', true);
  const [showSettings, setShowSettings] = useState(false);
  const [showClearConfirm, setShowClearConfirm] = useState(false);

  useEffect(() => {
    const initChat = async () => {
       const { data: { user } } = await supabase.auth.getUser();
       if (!user) return;
       setUserId(user.id);
       try {
           const history = await fetchChatHistory(user.id);
           setMessages(history.map(h => ({
               id: h.id, 
               role: h.is_user_message ? 'user' : 'model', 
               text: h.message, 
               timestamp: new Date(h.created_at).getTime(),
               plan_data: h.plan_data
           })));
       } finally { setIsLoading(false); }
    };
    initChat();
  }, []);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages, isTyping, isThinking]);

  const handleClearHistory = async () => {
    if (!userId) return;
    try {
      await clearChatHistory(userId);
      setMessages([]);
      setShowClearConfirm(false);
      setShowSettings(false);
    } catch (e) {
      console.error("Clear Error", e);
    }
  };

  /**
   * REFACTORED:
   * 1. Fetches real stats from DB right before sending.
   * 2. Injects conversational history for memory.
   * 3. Robust error handling.
   */
  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isTyping || !userId) return;

    const userText = input;

    // 1. UPDATE UI IMMEDIATELY
    const userMsg: ChatMessage = { 
      id: Date.now().toString(), 
      role: 'user', 
      text: userText, 
      timestamp: Date.now() 
    };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);
    if (thinkingMode) setIsThinking(true);

    // Save to DB in background
    saveChatMessage(userId, userText, true).catch(console.error);

    try {
      // 2. FETCH REAL-TIME DATA FROM SUPABASE
      const { data: freshProfile } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();

      // 3. FETCH LAST 10 MESSAGES FOR MEMORY
      // We use the local state which is already synced with DB on mount
      const historyContext: Content[] = messages
        .slice(-10) // Conversational memory: last 10
        .map(h => ({
          role: h.role,
          parts: [{ text: h.text }]
        }));

      // 4. CALL AI WITH DYNAMIC CONTEXT
      const stream = await getCoachChatStream(
        userText, 
        historyContext, 
        freshProfile || {}, 
        activity, 
        thinkingMode
      );

      const coachId = (Date.now() + 1).toString();
      let coachText = '';

      setMessages(prev => [...prev, { id: coachId, role: 'model', text: '', timestamp: Date.now() }]);
      setIsThinking(false);

      for await (const chunk of stream) {
        coachText += chunk.text || '';
        setMessages(prev => prev.map(m => m.id === coachId ? { ...m, text: coachText } : m));
      }

      // Sync Protocol Logic (Plan changes)
      const protocolMatch = coachText.match(/SYNC_PROTOCOL:\s*(\{.*\})/);
      let planData = null;
      if (protocolMatch) {
          try {
              planData = JSON.parse(protocolMatch[1]);
              await updateUserTargets(userId, planData);
              if (onUpdateTargets) onUpdateTargets(planData.calories, planData.steps, planData.plan_name);
              setMessages(prev => prev.map(m => m.id === coachId ? { ...m, plan_data: planData } : m));
          } catch (e) { console.error("Sync Failure", e); }
      }

      await saveChatMessage(userId, coachText, false, planData);

    } catch (error: any) {
      console.error("Coach protocol failure:", error);
      const friendlyError = "The elite neural network is recalibrating. I've logged your request and will be fully synchronized in a moment. Please try your query again.";
      setMessages(prev => [...prev, { 
        id: 'err-' + Date.now(), 
        role: 'model', 
        text: friendlyError, 
        timestamp: Date.now() 
      }]);
    } finally { 
      setIsTyping(false); 
      setIsThinking(false);
    }
  };

  if (isLoading) {
    return (
      <div className="h-full w-full bg-black flex items-center justify-center">
        <Loader2 className="animate-spin text-luxury-neon" />
      </div>
    );
  }

  return (
    <div className="h-full w-full flex flex-col bg-[#050505] relative font-sans">
      {/* Header */}
      <div className="p-6 pt-12 flex items-center justify-between border-b border-white/5 z-10 bg-black/40 backdrop-blur-md shrink-0">
        <div className="flex items-center gap-4">
          <div className={`w-12 h-12 rounded-full flex items-center justify-center border transition-all duration-700 ${thinkingMode ? 'border-luxury-neon/50 bg-luxury-neon/5 shadow-[0_0_20px_rgba(206,242,69,0.2)]' : 'border-white/10 bg-white/5'}`}>
            {thinkingMode ? <Brain size={24} className="text-luxury-neon" /> : <Zap size={24} className="text-gray-400" />}
          </div>
          <div>
            <h1 className="text-xl font-black text-white tracking-tight uppercase">AI Coach</h1>
            <div className="flex items-center gap-2">
              <span className={`text-[9px] uppercase font-black tracking-[0.2em] ${thinkingMode ? 'text-luxury-neon' : 'text-gray-500'}`}>
                 {thinkingMode ? 'Hyper-Intelligence' : 'Standard Response'}
              </span>
            </div>
          </div>
        </div>

        <button 
          onClick={() => setShowSettings(!showSettings)} 
          className={`p-3 rounded-full border transition-all ${showSettings ? 'bg-luxury-neon text-black border-luxury-neon' : 'bg-white/5 text-gray-500 border-white/10'}`}
        >
          <Settings2 size={18} />
        </button>
      </div>

      <AnimatePresence>
        {showSettings && (
          <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} className="bg-white/[0.02] border-b border-white/10 overflow-hidden shrink-0">
            <div className="p-6 space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-[10px] font-black text-white uppercase tracking-widest mb-1">Deep Reason Protocol</p>
                  <p className="text-[8px] text-gray-500 uppercase tracking-widest">Utilize Gemini 3 Pro (32K Budget)</p>
                </div>
                <button 
                  onClick={() => setThinkingMode(!thinkingMode)} 
                  className={`w-12 h-6 rounded-full relative transition-all duration-300 ${thinkingMode ? 'bg-luxury-neon' : 'bg-white/10'}`}
                >
                  <motion.div 
                    animate={{ x: thinkingMode ? 26 : 4 }}
                    className={`absolute top-1 w-4 h-4 rounded-full ${thinkingMode ? 'bg-black' : 'bg-gray-400'}`}
                  />
                </button>
              </div>

              <div className="h-px bg-white/5 w-full"></div>

              <div className="flex items-center justify-between">
                <div>
                  <p className="text-[10px] font-black text-red-500 uppercase tracking-widest mb-1">Erase Archive</p>
                  <p className="text-[8px] text-gray-500 uppercase tracking-widest">Wipe conversational history</p>
                </div>
                <button 
                  onClick={() => setShowClearConfirm(true)}
                  className="p-2 bg-red-500/10 text-red-500 rounded-lg hover:bg-red-500/20 transition-all"
                >
                  <Trash2 size={16} />
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <AnimatePresence>
        {showClearConfirm && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/80 backdrop-blur-sm">
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }} className="w-full max-w-sm glass-card p-8 rounded-3xl border border-white/10 text-center">
              <AlertCircle size={40} className="text-red-500 mx-auto mb-4" />
              <h2 className="text-xl font-black text-white uppercase tracking-tight mb-2">Clear Archive?</h2>
              <p className="text-xs text-gray-500 uppercase tracking-widest mb-8">This action will permanently wipe the chat history from our cloud servers.</p>
              <div className="flex flex-col gap-3">
                <button onClick={handleClearHistory} className="w-full py-4 bg-red-600 rounded-2xl text-white font-black text-xs uppercase tracking-widest">Confirm Deletion</button>
                <button onClick={() => setShowClearConfirm(false)} className="w-full py-4 bg-white/5 rounded-2xl text-white font-bold text-xs uppercase tracking-widest">Cancel</button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

      {/* Chat Area */}
      <div className="flex-1 overflow-hidden relative flex flex-col">
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 no-scrollbar">
          {messages.length === 0 && !isTyping && (
            <div className="h-full flex flex-col items-center justify-center text-center p-10 space-y-4 opacity-50">
              <div className="w-16 h-16 rounded-3xl bg-white/5 flex items-center justify-center border border-white/10 mb-4">
                <Sparkles size={32} className="text-luxury-neon" />
              </div>
              <h3 className="text-lg font-black text-white uppercase tracking-tight">System Ready</h3>
              <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest leading-relaxed">
                Your elite AI coach is synchronized with your biometrics. How can we optimize your status today?
              </p>
            </div>
          )}

          {messages.map((msg) => (
            <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                {msg.plan_data && (
                  <div className="mb-2 px-3 py-1 bg-luxury-neon/10 border border-luxury-neon/20 rounded-full text-[8px] font-black text-luxury-neon uppercase tracking-widest">
                    Protocol Synced: {msg.plan_data.plan_name}
                  </div>
                )}
                <div className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed ${msg.role === 'user' ? 'bg-luxury-neon text-black font-bold shadow-[0_4px_15px_rgba(206,242,69,0.15)]' : 'bg-white/5 text-white border border-white/5 backdrop-blur-sm'}`}>
                    {msg.text.replace(/SYNC_PROTOCOL:\s*\{.*\}/, '').trim()}
                </div>
            </div>
          ))}

          {isThinking && (
            <div className="flex flex-col items-start">
              <div className="bg-white/5 border border-white/5 p-4 rounded-2xl flex items-center gap-3">
                <div className="flex gap-1">
                  {[0, 1, 2].map(i => (
                    <motion.div key={i} animate={{ scale: [1, 1.5, 1], opacity: [0.3, 1, 0.3] }} transition={{ repeat: Infinity, delay: i * 0.2, duration: 1 }} className="w-1.5 h-1.5 bg-luxury-neon rounded-full" />
                  ))}
                </div>
                <span className="text-[9px] font-black text-gray-500 uppercase tracking-widest italic">Coordinating biometric context...</span>
              </div>
            </div>
          )}
        </div>

        {/* Input Bar */}
        <div className="p-6 pb-12 bg-black border-t border-white/10 shrink-0">
          <form onSubmit={handleSend} className="flex items-center gap-3">
            <input 
              type="text" 
              value={input} 
              onChange={(e) => setInput(e.target.value)} 
              placeholder="Ask for precise coaching..." 
              className="flex-1 bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-sm text-white placeholder-gray-700 outline-none focus:border-luxury-neon/40 transition-all shadow-inner" 
            />
            <button type="submit" disabled={isTyping || !input.trim()} className="w-14 h-14 rounded-2xl bg-luxury-neon text-black flex items-center justify-center disabled:opacity-30 active:scale-95 transition-all shadow-[0_0_20px_rgba(206,242,69,0.3)] shrink-0">
              {isTyping ? <Loader2 className="animate-spin" size={20} /> : <Send size={20} />}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

