/**
 * UPDATED: Injects real-time user profile data and activity metrics.
 * Now includes a fallback mechanism: If Pro fails with quota, it tries Flash.
 */
export const getCoachChatStream = async (
  message: string, 
  history: Content[], 
  profile: any, 
  activity: ActivityData,
  isThinkingMode: boolean = true
) => {
  const height = profile.height || 175;
  const weight = profile.weight || 70;
  const metrics = profile.metrics || {};
  const age = metrics.age || 25;
  const goal = metrics.fitnessGoal || 'Maintenance';
  const activityLevel = metrics.activityLevel || 'Moderately Active';

  const systemInstruction = `You are the Healthy.hub Elite AI Coach. 
  Persona: Wellness Concierge. Sophisticated, clinical, result-oriented.

  CURRENT BIO-DATA:
  - Height: ${height}cm, Weight: ${weight}kg, Age: ${age}, Goal: ${goal}, Activity: ${activityLevel}

  TODAY'S PROGRESS:
  - Steps: ${activity.steps}, Calories Burned: ${Math.floor(activity.calories)}

  PROTOCOL: 
  Provide precise fitness advice based on bio-data.
  If proposing a goal change, use sync token: SYNC_PROTOCOL: {"calories": [num], "steps": [num], "plan_name": "[string]"}
  History of 10 messages provided.`;

  const primaryModel = isThinkingMode ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';
  const fallbackModel = 'gemini-3-flash-preview';

  const generateConfig = (modelName: string) => {
    const config: any = { systemInstruction, temperature: 0.7 };
    if (modelName === 'gemini-3-pro-preview') {
      config.thinkingConfig = { thinkingBudget: 16384 }; // Reduced budget for better throughput
    }
    return config;
  };

  try {
    // Attempt with primary model
    return await ai.models.generateContentStream({ 
      model: primaryModel, 
      config: generateConfig(primaryModel), 
      contents: [{ role: 'user', parts: [{ text: message }] }] // Simplified for stream wrapper
    });
  } catch (error: any) {
    const errorStr = JSON.stringify(error);
    if (errorStr.includes("429") && primaryModel !== fallbackModel) {
      console.warn("Primary model quota hit. Falling back to Flash...");
      return await ai.models.generateContentStream({
        model: fallbackModel,
        config: generateConfig(fallbackModel),
        contents: [{ role: 'user', parts: [{ text: message }] }]
      });
    }
    return handleGenAIError(error);
  }
};

