export const generateWorkoutRoutine = async (
  level: string, 
  goal: string, 
  equipment: string, 
  duration: string,
  intensity: string,
  metrics: UserMetrics
): Promise<WorkoutPlan> => {
  return withRetry(async () => {
    try {
      const prompt = `Elite workout: H${metrics.height} W${metrics.weight} Goal:${goal} Lvl:${level} Int:${intensity} Dur:${duration} Equip:${equipment}. JSON format.`;

      // Fallback logic for workout generation too
      let model = 'gemini-3-pro-preview';
      try {
        const response = await ai.models.generateContent({
          model,
          contents: prompt,
          config: { 
            responseMimeType: "application/json", 
            responseSchema: workoutResponseSchema,
            thinkingConfig: { thinkingBudget: 16384 } 
          }
        });
        if (response.text) {
          const data = JSON.parse(response.text);
          return { id: Date.now().toString(), timestamp: Date.now(), ...data, intensity, equipment } as WorkoutPlan;
        }
      } catch (proError: any) {
        if (JSON.stringify(proError).includes("429")) {
          model = 'gemini-3-flash-preview';
          const response = await ai.models.generateContent({
            model,
            contents: prompt,
            config: { responseMimeType: "application/json", responseSchema: workoutResponseSchema }
          });
          if (response.text) {
            const data = JSON.parse(response.text);
            return { id: Date.now().toString(), timestamp: Date.now(), ...data, intensity, equipment } as WorkoutPlan;
          }
        }
        throw proError;
      }
      throw new Error("Generation failed.");
    } catch (error) { return handleGenAIError(error); }
  });
};

