      const plan = await generateWorkoutRoutine(
        'Intermediate', 
        goal || metrics.fitnessGoal || 'Optimize performance',
        equipment || 'Any available',
        duration || 'Standard session',
        intensity || 'Variable',
        metrics
      );
      setCurrentPlan(plan);
      setIsSavedInCurrentSession(false);
      setView('result');
