          reps: { type: Type.STRING },
          notes: { type: Type.STRING }
        },
        required: ["name", "sets", "reps", "notes"]
      }
    }
  },
  required: ["title", "difficulty", "duration", "exercises"]
};

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

const handleGenAIError = (error: any): never => {
  const errorStr = JSON.stringify(error);
  if (errorStr.includes("429") || errorStr.includes("RESOURCE_EXHAUSTED")) {
    throw new Error("QUOTA_EXHAUSTED: The elite neural network is currently at maximum capacity. Switching to power-save mode...");
  }
  console.error("Gemini API Error:", error);
  throw new Error(error.message || "AI Protocol Interrupted.");
};

async function withRetry<T>(fn: () => Promise<T>, maxRetries = 3): Promise<T> {
  let lastError;
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error: any) {
      lastError = error;
      const errorStr = JSON.stringify(error);
      if (errorStr.includes("429") || errorStr.includes("RESOURCE_EXHAUSTED")) {
        await sleep(Math.pow(2, i) * 1000);
        continue;
      }
      throw error;
    }
  }
  return handleGenAIError(lastError);
}

