import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Send, Sparkles, Loader2, Brain, Zap, Settings2, Trash2, AlertCircle, Info, CheckCircle2, ArrowRight } from 'lucide-react';
import { getCoachChatStream } from '../services/geminiService';
import { fetchChatHistory, saveChatMessage, supabase, updateUserTargets, clearChatHistory } from '../services/supabase';
import { ChatMessage, UserMetrics, ActivityData, UserProfile } from '../types';
import { Content } from '@google/genai';
import useLocalStorage from '../hooks/useLocalStorage';

interface ChatBotProps {
  metrics: UserMetrics;
  activity: ActivityData;
  onUpdateTargets?: (calories: number, steps: number, planName: string) => void;
}

const ChatBot: React.FC<ChatBotProps> = ({ metrics, activity, onUpdateTargets }) => {
  const [messages, setMessages] = useState<(ChatMessage & { plan_data?: any })[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isThinking, setIsThinking] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [applyingPlan, setApplyingPlan] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const [userId, setUserId] = useState<string | null>(null);

  const [thinkingMode, setThinkingMode] = useLocalStorage<boolean>('ai_thinking_mode', false);
  const [showSettings, setShowSettings] = useState(false);
  const [showClearConfirm, setShowClearConfirm] = useState(false);

  useEffect(() => {
    const initChat = async () => {
       const { data: { user } } = await supabase.auth.getUser();
       if (!user) return;
       setUserId(user.id);
       try {
           const history = await fetchChatHistory(user.id);
           setMessages(history.map(h => ({
               id: h.id, 
               role: h.is_user_message ? 'user' : 'model', 
               text: h.message, 
               timestamp: new Date(h.created_at).getTime(),
               plan_data: h.plan_data
           })));
       } finally { setIsLoading(false); }
    };
    initChat();
  }, []);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages, isTyping, isThinking]);

  const handleClearHistory = async () => {
    if (!userId) return;
    try {
      await clearChatHistory(userId);
      setMessages([]);
      setShowClearConfirm(false);
      setShowSettings(false);
    } catch (e) {
      console.error("Clear Error", e);
    }
  };

  const handleApplyPlan = async (msgId: string, planData: any) => {
    if (!userId) return;
    setApplyingPlan(msgId);
    try {
      await updateUserTargets(userId, planData);
      if (onUpdateTargets) {
        onUpdateTargets(
          planData.target_calories || planData.calories, 
          planData.target_steps || planData.steps, 
          planData.plan_name
        );
      }
      // UI update for this specific message
      setMessages(prev => prev.map(m => m.id === msgId ? { ...m, plan_applied: true } : m));
    } catch (e) {
      console.error("Apply Plan Failure", e);
    } finally {
      setApplyingPlan(null);
    }
  };

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isTyping || !userId) return;

    const userText = input;

    const userMsg: ChatMessage = { 
      id: Date.now().toString(), 
      role: 'user', 
      text: userText, 
      timestamp: Date.now() 
    };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);
    if (thinkingMode) setIsThinking(true);

    saveChatMessage(userId, userText, true).catch(console.error);

    try {
      const { data: freshProfile } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();

      const historyContext: Content[] = messages
        .slice(-10)
        .map(h => ({
          role: h.role,
          parts: [{ text: h.text }]
        }));

      const stream = await getCoachChatStream(
        userText, 
        historyContext, 
        freshProfile || {}, 
        activity, 
        thinkingMode
      );

      const coachId = (Date.now() + 1).toString();
      let coachText = '';

      setMessages(prev => [...prev, { id: coachId, role: 'model', text: '', timestamp: Date.now() }]);
      setIsThinking(false);

      for await (const chunk of stream) {
        coachText += chunk.text || '';
        setMessages(prev => prev.map(m => m.id === coachId ? { ...m, text: coachText } : m));
      }

      // Sync Protocol Logic (Plan detection)
      const protocolMatch = coachText.match(/SYNC_PROTOCOL:\s*(\{.*\})/);
      let planData = null;
      if (protocolMatch) {
          try {
              planData = JSON.parse(protocolMatch[1]);
              setMessages(prev => prev.map(m => m.id === coachId ? { ...m, plan_data: planData } : m));
          } catch (e) { console.error("Parse Failure", e); }
      }

      await saveChatMessage(userId, coachText, false, planData);

    } catch (error: any) {
      console.error("Coach protocol failure:", error);
      let errorMsg = "The elite neural network is recalibrating. I've logged your request and will be fully synchronized in a moment.";
      if (error.message?.includes("QUOTA_EXHAUSTED")) {
        errorMsg = "System Overload: The AI processing quota is reached. Try switching off 'Deep Reason Protocol' in settings.";
      }
      setMessages(prev => [...prev, { 
        id: 'err-' + Date.now(), 
        role: 'model', 
        text: errorMsg, 
        timestamp: Date.now() 
      }]);
    } finally { 
      setIsTyping(false); 
      setIsThinking(false);
    }
  };

  return (
    <div className="h-full w-full flex flex-col bg-[#050505] relative font-sans">
      {/* Header */}
      <div className="p-6 pt-12 flex items-center justify-between border-b border-white/5 z-10 bg-black/40 backdrop-blur-md shrink-0">
        <div className="flex items-center gap-4">
          <div className={`w-12 h-12 rounded-full flex items-center justify-center border transition-all duration-700 ${thinkingMode ? 'border-luxury-neon/50 bg-luxury-neon/5 shadow-[0_0_20px_rgba(206,242,69,0.2)]' : 'border-white/10 bg-white/5'}`}>
            {thinkingMode ? <Brain size={24} className="text-luxury-neon" /> : <Zap size={24} className="text-gray-400" />}
          </div>
          <div>
            <h1 className="text-xl font-black text-white tracking-tight uppercase">AI Coach</h1>
            <div className="flex items-center gap-2">
              <span className={`text-[9px] uppercase font-black tracking-[0.2em] ${thinkingMode ? 'text-luxury-neon' : 'text-gray-500'}`}>
                 {thinkingMode ? 'Hyper-Intelligence' : 'Eco Response'}
              </span>
            </div>
          </div>
        </div>

        <button 
          onClick={() => setShowSettings(!showSettings)} 
          className={`p-3 rounded-full border transition-all ${showSettings ? 'bg-luxury-neon text-black border-luxury-neon' : 'bg-white/5 text-gray-500 border-white/10'}`}
        >
          <Settings2 size={18} />
        </button>
      </div>

      <AnimatePresence>
        {showSettings && (
          <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} className="bg-white/[0.02] border-b border-white/10 overflow-hidden shrink-0">
            <div className="p-6 space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <div className="flex items-center gap-2">
                    <p className="text-[10px] font-black text-white uppercase tracking-widest">Deep Reason Protocol</p>
                    <Info size={10} className="text-gray-600" />
                  </div>
                  <p className="text-[8px] text-gray-500 uppercase tracking-widest">Uses more API quota (Gemini Pro)</p>
                </div>
                <button 
                  onClick={() => setThinkingMode(!thinkingMode)} 
                  className={`w-12 h-6 rounded-full relative transition-all duration-300 ${thinkingMode ? 'bg-luxury-neon' : 'bg-white/10'}`}
                >
                  <motion.div 
                    animate={{ x: thinkingMode ? 26 : 4 }}
                    className={`absolute top-1 w-4 h-4 rounded-full ${thinkingMode ? 'bg-black' : 'bg-gray-400'}`}
                  />
                </button>
              </div>
              <div className="h-px bg-white/5 w-full"></div>
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-[10px] font-black text-red-500 uppercase tracking-widest mb-1">Erase Archive</p>
                  <p className="text-[8px] text-gray-500 uppercase tracking-widest">Wipe conversational history</p>
                </div>
                <button 
                  onClick={() => setShowClearConfirm(true)}
                  className="p-2 bg-red-500/10 text-red-500 rounded-lg hover:bg-red-500/20 transition-all"
                >
                  <Trash2 size={16} />
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <div className="flex-1 overflow-hidden relative flex flex-col">
        <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 no-scrollbar">
          {messages.length === 0 && !isTyping && (
            <div className="h-full flex flex-col items-center justify-center text-center p-10 space-y-4 opacity-50">
              <div className="w-16 h-16 rounded-3xl bg-white/5 flex items-center justify-center border border-white/10 mb-4">
                <Sparkles size={32} className="text-luxury-neon" />
              </div>
              <h3 className="text-lg font-black text-white uppercase tracking-tight">System Ready</h3>
              <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest leading-relaxed">
                Your elite AI coach is synchronized. How can we optimize your status today?
              </p>
            </div>
          )}

          {messages.map((msg) => (
            <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                <div className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed ${msg.role === 'user' ? 'bg-luxury-neon text-black font-bold shadow-[0_4px_15px_rgba(206,242,69,0.15)]' : 'bg-white/5 text-white border border-white/5 backdrop-blur-sm'}`}>
                    {msg.text.replace(/SYNC_PROTOCOL:\s*\{.*\}/, '').trim()}
                </div>

                {/* Detect SYNC_PROTOCOL JSON and show the "APPLY PLAN" button */}
                {msg.plan_data && (
                  <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="mt-3 w-full max-w-[80%]">
                    <div className="glass-card rounded-2xl border border-luxury-neon/20 p-4 bg-luxury-neon/5">
                      <div className="flex items-center gap-3 mb-3">
                         <div className="w-8 h-8 rounded-full bg-luxury-neon/10 flex items-center justify-center text-luxury-neon">
                            <Sparkles size={16} />
                         </div>
                         <h4 className="text-[11px] font-black text-white uppercase tracking-widest">{msg.plan_data.plan_name || 'Optimization Protocol'}</h4>
                      </div>

                      <div className="grid grid-cols-2 gap-3 mb-4">
                        <div className="text-center p-2 bg-white/5 rounded-xl border border-white/5">
                          <p className="text-[8px] font-bold text-gray-500 uppercase mb-1">Steps</p>
                          <p className="text-xs font-black text-white">{msg.plan_data.target_steps || msg.plan_data.steps}</p>
                        </div>
                        <div className="text-center p-2 bg-white/5 rounded-xl border border-white/5">
                          <p className="text-[8px] font-bold text-gray-500 uppercase mb-1">Calories</p>
                          <p className="text-xs font-black text-white">{msg.plan_data.target_calories || msg.plan_data.calories}</p>
                        </div>
                      </div>

                      <button 
                        onClick={() => handleApplyPlan(msg.id, msg.plan_data)}
                        disabled={(msg as any).plan_applied || applyingPlan === msg.id}
                        className={`w-full py-3 rounded-xl flex items-center justify-center gap-2 text-[10px] font-black uppercase tracking-[0.2em] transition-all ${
                          (msg as any).plan_applied 
                            ? 'bg-green-500/20 text-green-400 border border-green-500/30' 
                            : 'bg-luxury-neon text-black shadow-[0_0_15px_rgba(206,242,69,0.2)]'
                        }`}
                      >
                        {(msg as any).plan_applied ? <><CheckCircle2 size={14} /> Protocol Applied</> : applyingPlan === msg.id ? <Loader2 size={14} className="animate-spin" /> : <><ArrowRight size={14} /> Sync to Profile</>}
                      </button>
                    </div>
                  </motion.div>
                )}
            </div>
          ))}

          {isThinking && (
            <div className="flex flex-col items-start">
              <div className="bg-white/5 border border-white/5 p-4 rounded-2xl flex items-center gap-3">
                <div className="flex gap-1">
                  {[0, 1, 2].map(i => (
                    <motion.div key={i} animate={{ scale: [1, 1.5, 1], opacity: [0.3, 1, 0.3] }} transition={{ repeat: Infinity, delay: i * 0.2, duration: 1 }} className="w-1.5 h-1.5 bg-luxury-neon rounded-full" />
                  ))}
                </div>
                <span className="text-[9px] font-black text-gray-500 uppercase tracking-widest italic">Reasoning in progress...</span>
              </div>
            </div>
          )}
        </div>

        {/* Input Bar */}
        <div className="p-6 pb-12 bg-black border-t border-white/10 shrink-0">
          <form onSubmit={handleSend} className="flex items-center gap-3">
            <input 
              type="text" 
              value={input} 
              onChange={(e) => setInput(e.target.value)} 
              placeholder="Ask for precise coaching..." 
              className="flex-1 bg-white/5 border border-white/10 rounded-2xl px-5 py-4 text-sm text-white placeholder-gray-700 outline-none focus:border-luxury-neon/40 transition-all shadow-inner" 
            />
            <button type="submit" disabled={isTyping || !input.trim()} className="w-14 h-14 rounded-2xl bg-luxury-neon text-black flex items-center justify-center disabled:opacity-30 active:scale-95 transition-all shadow-[0_0_20px_rgba(206,242,69,0.3)] shrink-0">
              {isTyping ? <Loader2 className="animate-spin" size={20} /> : <Send size={20} />}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default ChatBot;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Dumbbell, Play, Timer, Zap, ChevronRight, Save, Trash2, 
  Loader2, CheckCircle, Sparkles, Plus, Clock, Info, 
  ShieldCheck, RefreshCw, X, ArrowLeft, Target, AlertTriangle, BrainCircuit
} from 'lucide-react';
import { generateWorkoutRoutine } from '../services/geminiService';
import { supabase, fetchSavedWorkouts, saveWorkout, deleteWorkout } from '../services/supabase';
import { WorkoutPlan, UserMetrics, FitnessGoal } from '../types';

interface WorkoutLabProps {
  metrics: UserMetrics;
}

const WorkoutLab: React.FC<WorkoutLabProps> = ({ metrics }) => {
  const [view, setView] = useState<'selection' | 'generating' | 'result' | 'history'>('selection');
  const [savedWorkouts, setSavedWorkouts] = useState<any[]>([]);
  const [loadingHistory, setLoadingHistory] = useState(true);
  const [generating, setGenerating] = useState(false);

  // Selection State - Now using free text
  const [duration, setDuration] = useState('');
  const [intensity, setIntensity] = useState('');
  const [equipment, setEquipment] = useState('');
  const [goal, setGoal] = useState('');

  const [currentPlan, setCurrentPlan] = useState<WorkoutPlan | null>(null);
  const [isSavedInCurrentSession, setIsSavedInCurrentSession] = useState(false);
  const [userId, setUserId] = useState<string | null>(null);

  const [safetyAdvice, setSafetyAdvice] = useState<string | null>(null);

  useEffect(() => {
    const init = async () => {
      const { data: { user } } = await supabase.auth.getUser();
      if (user) {
        setUserId(user.id);
        const history = await fetchSavedWorkouts(user.id);
        setSavedWorkouts(history);
      }
      setLoadingHistory(false);
    };
    init();
  }, []);

  // Simple Logic Check for Safety / Goal alignment
  useEffect(() => {
    if (intensity.toLowerCase().includes('elite') || intensity.toLowerCase().includes('extreme')) {
        if (metrics.weight > 100) {
            setSafetyAdvice("Impact warning: high weight + extreme intensity detected. Consider low-impact variants to protect joints.");
        } else {
            setSafetyAdvice(null);
        }
    } else if (duration.toLowerCase().includes('hour') && metrics.activityLevel === 'Sedentary') {
        setSafetyAdvice("Endurance warning: 1h+ sessions might be excessive for current base activity. Consider scaling to 30m.");
    } else {
        setSafetyAdvice(null);
    }
  }, [duration, intensity, metrics]);

  const handleGenerate = async () => {
    setGenerating(true);
    setView('generating');
    try {
      const plan = await generateWorkoutRoutine(
        'Intermediate', 
        goal || metrics.fitnessGoal || 'Optimize performance',
        equipment || 'Any available',
        duration || 'Standard session',
        intensity || 'Variable',
        metrics
      );
      setCurrentPlan(plan);
      setIsSavedInCurrentSession(false);
      setView('result');
    } catch (e) {
      console.error(e);
      setView('selection');
    } finally {
      setGenerating(false);
    }
  };

  const handleSavePlan = async () => {
    if (!userId || !currentPlan || isSavedInCurrentSession) return;
    try {
      await saveWorkout(userId, currentPlan);
      setIsSavedInCurrentSession(true);
      const history = await fetchSavedWorkouts(userId);
      setSavedWorkouts(history);
    } catch (e) {
      console.error(e);
    }
  };

  const handleDeleteSaved = async (id: string) => {
    try {
      await deleteWorkout(id);
      setSavedWorkouts(prev => prev.filter(w => w.id !== id));
    } catch (e) {
      console.error(e);
    }
  };

  if (loadingHistory) {
    return (
      <div className="h-full w-full bg-black flex flex-col items-center justify-center">
        <Loader2 className="animate-spin text-luxury-neon" size={40} />
      </div>
    );
  }

  const isSelectionValid = duration.trim() || intensity.trim() || equipment.trim() || goal.trim();

  return (
    <div className="h-full w-full bg-black flex flex-col overflow-hidden relative font-sans">

      {/* Header */}
      <div className="p-8 pt-16 flex justify-between items-center z-10 shrink-0">
        <div>
          <h1 className="text-3xl font-black text-white tracking-tighter">ELITE <span className="text-luxury-neon">LAB</span></h1>
          <p className="text-[10px] font-black text-gray-500 uppercase tracking-[0.4em] mt-1">Neural Workout Synth</p>
        </div>
        <button 
          onClick={() => setView(view === 'history' ? 'selection' : 'history')}
          className="w-12 h-12 glass-card rounded-2xl flex items-center justify-center border border-white/10 active:scale-95 transition-all"
        >
          {view === 'history' ? <Plus size={20} className="text-luxury-neon" /> : <Clock size={20} className="text-gray-400" />}
        </button>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar pb-32">
        <AnimatePresence mode="wait">

          {/* SELECTION VIEW */}
          {view === 'selection' && (
            <motion.div 
              key="selection" 
              initial={{ opacity: 0, y: 20 }} 
              animate={{ opacity: 1, y: 0 }} 
              exit={{ opacity: 0, scale: 0.95 }}
              className="px-8 space-y-8"
            >
              <div className="space-y-6">
                <LuxuryTextField 
                  label="Training Duration" 
                  value={duration} 
                  onChange={setDuration} 
                  placeholder="e.g. 45 minutes"
                  icon={<Timer size={16} />}
                />

                <LuxuryTextField 
                  label="Intensity Protocol" 
                  value={intensity} 
                  onChange={setIntensity} 
                  placeholder="e.g. High Intensity Interval Training"
                  icon={<Zap size={16} />}
                />

                <LuxuryTextField 
                  label="Equipment Availability" 
                  value={equipment} 
                  onChange={setEquipment} 
                  placeholder="e.g. Dumbbells, Resistance Bands"
                  icon={<Dumbbell size={16} />}
                />

                <LuxuryTextField 
                  label="Focus Objective" 
                  value={goal} 
                  onChange={setGoal} 
                  placeholder="e.g. Muscle Gain & Fat Loss"
                  icon={<Target size={16} />}
                />
              </div>

              {safetyAdvice && (
                <motion.div initial={{ opacity: 0, x: -10 }} animate={{ opacity: 1, x: 0 }} className="bg-orange-500/10 border border-orange-500/20 p-4 rounded-2xl flex items-start gap-3">
                    <AlertTriangle className="text-orange-500 shrink-0" size={16} />
                    <p className="text-[10px] font-black text-orange-200 uppercase tracking-widest leading-relaxed">{safetyAdvice}</p>
                </motion.div>
              )}

              <div className="pt-4">
                <button 
                  onClick={handleGenerate}
                  className="w-full py-6 bg-luxury-neon text-black font-black uppercase tracking-[0.2em] rounded-[2rem] shadow-[0_0_30px_rgba(206,242,69,0.3)] flex items-center justify-center gap-3 active:scale-95 transition-all disabled:opacity-50"
                  disabled={!isSelectionValid}
                >
                  <Sparkles size={20} /> Synthesize Routine
                </button>
              </div>
            </motion.div>
          )}

          {/* GENERATING VIEW */}
          {view === 'generating' && (
            <motion.div 
              key="generating" 
              initial={{ opacity: 0 }} 
              animate={{ opacity: 1 }} 
              className="px-8 flex flex-col items-center justify-center h-full text-center py-20"
            >
              <div className="relative mb-12">
                <div className="w-32 h-32 rounded-full border-2 border-white/5 border-t-luxury-neon animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center">
                  <BrainCircuit className="text-luxury-neon animate-pulse" size={40} />
                </div>
              </div>
              <h2 className="text-2xl font-black text-white tracking-tighter mb-4 uppercase">Optimizing Protocol</h2>
              <p className="text-xs text-gray-500 uppercase tracking-widest leading-relaxed max-w-xs mx-auto">
                Analyzing biometric signatures and manual constraints...
              </p>
            </motion.div>
          )}

          {/* RESULT VIEW */}
          {view === 'result' && currentPlan && (
            <motion.div 
              key="result" 
              initial={{ opacity: 0, x: 20 }} 
              animate={{ opacity: 1, x: 0 }} 
              className="px-8 space-y-8"
            >
              <div className="flex items-center gap-4 p-6 glass-card rounded-[2rem] border border-luxury-neon/20">
                <div className="w-14 h-14 rounded-2xl bg-luxury-neon/10 flex items-center justify-center text-luxury-neon">
                  <ShieldCheck size={28} />
                </div>
                <div>
                  <h3 className="text-xl font-black text-white tracking-tight">{currentPlan.title}</h3>
                  <div className="flex gap-4 mt-1">
                    <span className="text-[9px] font-black text-gray-500 uppercase tracking-widest">{currentPlan.duration}</span>
                    <span className="text-[9px] font-black text-luxury-neon uppercase tracking-widest">{currentPlan.intensity} Intensity</span>
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                {currentPlan.exercises.map((ex, i) => (
                  <div key={i} className="p-6 bg-white/5 border border-white/5 rounded-3xl space-y-3">
                    <div className="flex justify-between items-start">
                      <h4 className="font-black text-white text-lg">{ex.name}</h4>
                      <div className="px-3 py-1 bg-white/5 rounded-full text-[10px] font-black text-luxury-neon uppercase tracking-widest">
                        {ex.sets} × {ex.reps}
                      </div>
                    </div>
                    <p className="text-xs text-gray-500 leading-relaxed italic">
                      "{ex.notes}"
                    </p>
                  </div>
                ))}
              </div>

              <div className="flex gap-4 pt-4">
                <button 
                  onClick={() => setView('selection')}
                  className="flex-1 py-5 bg-white/5 text-white font-black uppercase text-[10px] tracking-[0.2em] rounded-[2rem] border border-white/10"
                >
                  Discard
                </button>
                <button 
                  onClick={handleSavePlan}
                  disabled={isSavedInCurrentSession}
                  className={`flex-1 py-5 font-black uppercase text-[10px] tracking-[0.2em] rounded-[2rem] flex items-center justify-center gap-2 transition-all ${isSavedInCurrentSession ? 'bg-green-500/20 text-green-500 border border-green-500/20' : 'bg-luxury-neon text-black shadow-lg shadow-luxury-neon/20'}`}
                >
                  {isSavedInCurrentSession ? <><CheckCircle size={16} /> Routine Stored</> : <><Save size={16} /> Save Routine</>}
                </button>
              </div>
            </motion.div>
          )}

          {/* HISTORY VIEW */}
          {view === 'history' && (
            <motion.div 
              key="history" 
              initial={{ opacity: 0 }} 
              animate={{ opacity: 1 }} 
              className="px-8 space-y-6"
            >
              <div className="flex items-center gap-2 mb-2">
                <Clock size={14} className="text-gray-500" />
                <h3 className="text-[10px] font-black text-gray-500 uppercase tracking-[0.2em]">Archived Sequences</h3>
              </div>

              {savedWorkouts.length === 0 ? (
                <div className="p-20 text-center glass-card rounded-[2rem] border border-dashed border-white/10 opacity-50">
                  <p className="text-xs font-black uppercase tracking-widest text-gray-600">No stored protocols</p>
                </div>
              ) : (
                <div className="space-y-4">
                  {savedWorkouts.map((w) => (
                    <div key={w.id} className="p-6 glass-card rounded-[2rem] border border-white/5 group relative">
                      <div className="flex justify-between items-start mb-4">
                        <div>
                          <h4 className="font-black text-white text-lg">{w.plan_data.title}</h4>
                          <p className="text-[9px] text-gray-600 font-bold uppercase tracking-widest mt-1">
                            {new Date(w.created_at).toLocaleDateString()} • {w.plan_data.duration}
                          </p>
                        </div>
                        <button 
                          onClick={() => handleDeleteSaved(w.id)}
                          className="p-2 text-gray-700 hover:text-red-500 transition-colors"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                      <button 
                        onClick={() => {
                          setCurrentPlan(w.plan_data);
                          setIsSavedInCurrentSession(true);
                          setView('result');
                        }}
                        className="w-full py-3 bg-white/5 rounded-xl text-[9px] font-black text-luxury-neon uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-white/10 transition-all"
                      >
                        Launch Protocol <ChevronRight size={12} />
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </motion.div>
          )}

        </AnimatePresence>
      </div>
    </div>
  );
};

