import { createClient, type User } from '@supabase/supabase-js';
import { ActivityData, UserMetrics, UserProfile, DailyActivityDB, FoodLogDB, ChatHistoryDB, SavedWorkoutDB } from '../types';

export type { User } from '@supabase/supabase-js';

// --- CONFIGURATION ---
const SUPABASE_URL = 'https://tngzcpgoshpfwuarskul.supabase.co';
const SUPABASE_ANON_KEY = 'sb_publishable_OyoWs8f9j8fNI9Y4YbPilg_tFtAQUNX';

export const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY, {
  auth: {
    detectSessionInUrl: false,
    persistSession: true,
    autoRefreshToken: true,
  }
});

export const DEFAULT_AVATAR = "https://upload.wikimedia.org/wikipedia/commons/8/89/Portrait_Placeholder.png";

// --- DATE HELPER ---
export const getLocalTodayKey = (): string => {
  const now = new Date();
  const year = now.getFullYear();
  const month = String(now.getMonth() + 1).padStart(2, '0');
  const day = String(now.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

// --- GUEST LOGIC ---
const GUEST_KEY = 'healthy_hub_guest_session';

export const isGuest = (userId: string | undefined): boolean => {
  if (!userId) return false;
  return userId.startsWith('guest_') || localStorage.getItem(GUEST_KEY) === 'true';
};

export const getGuestUser = (): User => ({
  id: 'guest_elite_member',
  email: 'guest@healthyhub.com',
  app_metadata: {},
  user_metadata: { full_name: 'Guest Elite' },
  aud: 'authenticated',
  created_at: new Date().toISOString()
});

// Added: Guest sign in logic
export const signInAsGuest = () => {
  localStorage.setItem(GUEST_KEY, 'true');
  window.location.reload();
};

// --- SYNC FUNCTION ---
/**
 * Persists daily activity to Supabase using an upsert logic.
 * Ensures that if a record exists, it is updated; otherwise, a new one is created.
 */
export const syncDailyActivity = async (userId: string, steps: number, calories: number, stepGoal: number, distanceKm: number = 0) => {
  if (isGuest(userId)) return;

  const todayKey = getLocalTodayKey();
  const isTargetMet = steps >= stepGoal;

  try {
    const { error } = await supabase.from('daily_activity').upsert({ 
      user_id: userId, 
      activity_date: todayKey, 
      steps: steps, 
      calories_burned: calories, 
      distance_km: distanceKm,
      is_target_met: isTargetMet,
      updated_at: new Date().toISOString()
    }, { 
      onConflict: 'user_id, activity_date' 
    });
    if (error) throw error;
  } catch (e) {
    console.error(`❌ ERROR SAVING ACTIVITY:`, e);
  }
};

// --- FETCH FUNCTION ---
/**
 * Loads the complete dashboard state for the user, including profile, today's activity,
 * food logs, and chat history.
 */
export const fetchFullUserDashboard = async (userId: string) => {
  if (isGuest(userId)) {
    return {
      profile: {
        id: userId,
        name: 'Guest Elite',
        email: 'guest@healthyhub.com',
        avatarUrl: DEFAULT_AVATAR,
        goals: { stepGoal: 10000, calorieGoal: 2000, distanceGoal: 5.0 },
        metrics: {}
      },
      todayActivity: null,
      foodLogs: [],
      chatHistory: []
    };
  }

  try {
    const todayKey = getLocalTodayKey();

    // 1. Fetch Profile
    const { data: profileData, error: profileError } = await supabase
      .from('profiles')
      .select('*')
      .eq('id', userId)
      .maybeSingle();

    if (profileError) {
       console.error("⚠️ Supabase Profile Fetch Error:", profileError);
    }

    if (!profileData) return null;

    // 2. Fetch Today's Activity
    const { data: activityData, error: activityError } = await supabase
      .from('daily_activity')
      .select('*')
      .eq('user_id', userId)
      .eq('activity_date', todayKey)
      .maybeSingle();

    if (activityError) {
       console.warn("⚠️ Supabase Activity Fetch Error:", activityError);
    }

    // 3. Parallel fetch logs and history
    const [foodRes, chatRes] = await Promise.all([
      supabase.from('food_logs').select('*').eq('user_id', userId).order('created_at', { ascending: false }).limit(20),
      supabase.from('chat_history').select('*').eq('user_id', userId).order('created_at', { ascending: true }).limit(50)
    ]);

    return {
      profile: mapProfileToAppFormat(profileData),
      todayActivity: activityData || null,
      foodLogs: foodRes.data as FoodLogDB[] || [],
      chatHistory: chatRes.data as ChatHistoryDB[] || []
    };
  } catch (e) {
    console.error("Critical Fetch Error:", e);
    return null;
  }
};

const mapProfileToAppFormat = (dbProfile: any): UserProfile => {
  const safeGoals = dbProfile.goals || {};
  return {
    id: dbProfile.id,
    name: dbProfile.name || 'Elite Member',
    email: dbProfile.email || '',
    avatarUrl: dbProfile.avatar_url || DEFAULT_AVATAR,
    currentStreak: dbProfile.current_streak || 0,
    currentPlanName: dbProfile.current_plan_name,
    goals: {
        stepGoal: dbProfile.target_steps || dbProfile.daily_step_goal || safeGoals.stepGoal || 10000,
        calorieGoal: dbProfile.target_calories || dbProfile.daily_calorie_goal || safeGoals.calorieGoal || 2000,
        proteinGoal: dbProfile.target_protein || safeGoals.proteinGoal || 150,
        distanceGoal: Number(safeGoals.distanceGoal) || 5.0
    },
    metrics: dbProfile.metrics || {}
  };
};

export const onAuthStateChanged = (callback: (user: User | null) => void) => {
  const guestActive = localStorage.getItem(GUEST_KEY) === 'true';
  if (guestActive) callback(getGuestUser());

  return supabase.auth.onAuthStateChange((_event, session) => {
    if (session?.user) {
      localStorage.removeItem(GUEST_KEY);
      callback(session.user);
    } else if (!guestActive) {
      callback(null);
    }
  }).data.subscription.unsubscribe;
};

export const signInWithEmailAndPassword = async (email: string, psw: string) => {
  const { data, error } = await supabase.auth.signInWithPassword({ email, password: psw });
  if (error) throw error;
  localStorage.removeItem(GUEST_KEY);
  return data;
};

export const signOut = async () => {
  try {
    localStorage.removeItem(GUEST_KEY);
    await supabase.auth.signOut({ scope: 'local' });
  } catch (err) {
    console.error("Supabase signOut error:", err);
    localStorage.removeItem(GUEST_KEY);
  }
};

export const createUserWithEmailAndPassword = async (email: string, psw: string) => {
  const { data, error } = await supabase.auth.signUp({ email, password: psw });
  if (error) throw error;
  localStorage.removeItem(GUEST_KEY);
  return { data };
};

export const createUserDocument = async (user: User, name: string) => {
  if (isGuest(user.id)) return;
  const { error } = await supabase.from('profiles').upsert({ id: user.id, email: user.email, name, avatar_url: DEFAULT_AVATAR });
  if (error) throw error;
};

// Added: Global profile update function for name and avatar
export const updateProfile = async (user: User, profile: { displayName?: string, photoURL?: string }) => {
  if (isGuest(user.id)) return;

  // Update Auth User Metadata
  const { error: authError } = await supabase.auth.updateUser({
    data: { 
      full_name: profile.displayName,
      avatar_url: profile.photoURL
    }
  });
  if (authError) throw authError;

  // Update Profiles table
  const updateData: any = {};
  if (profile.displayName) updateData.name = profile.displayName;
  if (profile.photoURL) updateData.avatar_url = profile.photoURL;

  if (Object.keys(updateData).length > 0) {
    const { error: profileError } = await supabase
      .from('profiles')
      .update(updateData)
      .eq('id', user.id);
    if (profileError) throw profileError;
  }
};

// Added: Password reset logic
export const sendPasswordResetEmail = async (email: string) => {
  const { error } = await supabase.auth.resetPasswordForEmail(email, {
    redirectTo: window.location.origin,
  });
  if (error) throw error;
};

export const updateUserMetrics = async (uid: string, metrics: UserMetrics) => {
  if (isGuest(uid)) return null;
  const { data, error } = await supabase.from('profiles').update({ metrics, weight: metrics.weight, height: metrics.height }).eq('id', uid);
  if (error) throw error;
  return data;
};

export const updateUserTargets = async (userId: string, targets: any) => {
  if (isGuest(userId)) return null;
  const { data, error } = await supabase.from('profiles').update({ 
    target_calories: targets.target_calories || targets.calories, 
