export const fetchStreakCalendarData = async (userId: string) => {
  if (isGuest(userId)) return { streakDates: [] };
  const { data, error } = await supabase.from('daily_activity').select('activity_date').eq('user_id', userId).eq('is_target_met', true);
  if (error) throw error;
