  const [error, setError] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);

  // Cooldown State
  const [lockoutTimer, setLockoutTimer] = useState(0);

  // Remember Me State
  const [rememberMe, setRememberMe] = useState(false);

  // Avatar Capture State
  const [showCamera, setShowCamera] = useState(false);
  const [tempUser, setTempUser] = useState<User | null>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const [isResetModalOpen, setIsResetModalOpen] = useState(false);
  const [resetEmail, setResetEmail] = useState('');
  const [resetError, setResetError] = useState<string | null>(null);
  const [resetSuccess, setResetSuccess] = useState<string | null>(null);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  // --- INIT: CHECK LOCAL STORAGE & COOLDOWN ---
  useEffect(() => {
    const savedEmail = localStorage.getItem('healthy_hub_remembered_email');
    if (savedEmail) {
      setEmail(savedEmail);
      setRememberMe(true);
    }
  }, []);

  useEffect(() => {
    let interval: number;
    if (lockoutTimer > 0) {
      interval = window.setInterval(() => {
        setLockoutTimer((prev) => prev - 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [lockoutTimer]);

  // --- CAMERA FUNCTIONS ---
  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'user', width: { ideal: 500 }, height: { ideal: 500 } }
      });
      setStream(mediaStream);
      setTimeout(() => {
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
          videoRef.current.play().catch(e => console.error("Video play failed", e));
        }
      }, 100);
    } catch (err) {
      setError("Could not access camera for profile photo.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(t => t.stop());
      setStream(null);
    }
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const size = Math.min(video.videoWidth, video.videoHeight);
      canvas.width = size;
      canvas.height = size;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        const startX = (video.videoWidth - size) / 2;
        const startY = (video.videoHeight - size) / 2;
        ctx.drawImage(video, startX, startY, size, size, 0, 0, size, size);
        const base64 = canvas.toDataURL('image/jpeg', 0.8);
        setCapturedImage(base64);
        stopCamera();
      }
    }
  };

  const handleRetake = () => {
    setCapturedImage(null);
    startCamera();
  };

  const handleSaveAvatar = async () => {
    if (!capturedImage || !tempUser) return;
    setIsLoading(true);
    try {
      await updateProfile(tempUser, { photoURL: capturedImage });
      onLoginSuccess();
    } catch (e) {
      setError("Failed to save profile photo.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleSkipAvatar = () => {
    stopCamera();
    onLoginSuccess();
  };

  const handleGuestMode = () => {
    setIsLoading(true);
    signInAsGuest(); // This will reload and bypass auth
  };

  // --- AUTH LOGIC ---
  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    if (lockoutTimer > 0) return;

    setError(null);
    setSuccessMsg(null);
    setIsLoading(true);

    const performAuth = async () => {
      if (isLogin) {
        const data = await signInWithEmailAndPassword(email, password);
        if (rememberMe) {
          localStorage.setItem('healthy_hub_remembered_email', email);
        } else {
          localStorage.removeItem('healthy_hub_remembered_email');
        }
        onLoginSuccess();
      } else {
        if (password !== confirmPassword) throw new Error("Passwords do not match.");
        if (password.length < 6) throw new Error("Password must be at least 6 characters.");
        const { data } = await createUserWithEmailAndPassword(email, password);
        if (rememberMe) {
          localStorage.setItem('healthy_hub_remembered_email', email);
        } else {
          localStorage.removeItem('healthy_hub_remembered_email');
        }
        const user = data.user;
        if (user) {
            if (name) {
                await updateProfile(user, { displayName: name });
                await createUserDocument(user, name);
            } else {
                await createUserDocument(user, 'Elite User');
            }
            setTempUser(user);
            setShowCamera(true);
            startCamera();
        }
      }
    };

    try {
      await performAuth();
    } catch (err: any) {
      console.error('❌ AUTH ERROR:', err);

      // QUOTA RECOVERY LOGIC
      if (err.message?.toLowerCase().includes('quota') || err.name === 'QuotaExceededError') {
        console.warn("Storage Quota hit during auth. Clearing non-essential data and retrying...");
        localStorage.removeItem('food_history');
        localStorage.removeItem('healthy_hub_db');
        try {
          // One single retry after clearing space
          await performAuth();
          return;
        } catch (retryErr: any) {
          setError("Device storage is completely full. Please clear some space in your browser settings to continue.");
          setIsLoading(false);
          return;
        }
      }

      let msg = err.message || "Authentication failed.";
      const lowerMsg = msg.toLowerCase();

      if (lowerMsg.includes("rate limit") || lowerMsg.includes("too many requests") || lowerMsg.includes("throttled")) {
        msg = "Too many attempts. Authentication throttled. Please wait 60 seconds.";
        setLockoutTimer(60);
      } else if (lowerMsg.includes("invalid login credentials") || lowerMsg.includes("user not found")) {
        msg = "Account not found. Verify your credentials or Sign Up.";
      } else if (lowerMsg.includes("email already in use")) {
        msg = "This email is already registered. Try logging in.";
      }

      setError(msg);
    } finally {
      setIsLoading(false);
    }
  };

  const handleResetPassword = async () => {
    if (!resetEmail) return;
    setResetError(null);
    setResetSuccess(null);
    try {
        await sendPasswordResetEmail(resetEmail);
        setResetSuccess("Recovery link sent to " + resetEmail);
        setTimeout(() => setIsResetModalOpen(false), 3000);
    } catch(err: any) {
        setResetError(err.message || "Failed to send reset link.");
    }
  };

  return (
    <div className="h-screen w-full flex flex-col bg-black font-sans relative overflow-y-auto no-scrollbar scroll-smooth">
      {/* Background stays fixed */}
      <div className="fixed inset-0 z-0 bg-cover bg-center grayscale blur-md opacity-40 scale-105 pointer-events-none"
        style={{ backgroundImage: 'url("https://images.unsplash.com/photo-1534438327276-14e5300c3a48?q=80&w=2070&auto=format&fit=crop")' }} />
      <div className="fixed inset-0 z-0 bg-gradient-to-b from-black/80 via-black/90 to-black pointer-events-none"></div>

      <AnimatePresence>
        {showCamera && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 bg-black flex flex-col items-center justify-center p-6"
          >
             <div className="w-full max-md flex flex-col items-center space-y-8">
                <div className="text-center">
                   <h2 className="text-2xl font-black text-white uppercase tracking-widest mb-2">Bio-Identity</h2>
                   <p className="text-gray-400 text-xs">Capture your profile avatar for the elite network.</p>
                </div>
                <div className="relative w-64 h-64 rounded-full overflow-hidden border-4 border-luxury-neon shadow-[0_0_40px_rgba(206,242,69,0.3)] bg-gray-900">
                    {capturedImage ? (
                        <img src={capturedImage} className="w-full h-full object-cover" alt="Captured" />
                    ) : (
                        <>
                           <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover mirror-mode" />
                           <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                              {!stream && <Loader2 className="animate-spin text-luxury-neon" />}
                           </div>
                        </>
                    )}
                </div>
                <canvas ref={canvasRef} className="hidden" />
                <div className="flex gap-4 w-full max-w-xs">
                   {capturedImage ? (
                      <>
                        <button onClick={handleRetake} className="flex-1 py-4 bg-white/10 rounded-2xl text-white font-bold flex items-center justify-center gap-2">
                           <RefreshCw size={18} /> Retake
                        </button>
                        <button onClick={handleSaveAvatar} disabled={isLoading} className="flex-1 py-4 bg-luxury-neon rounded-2xl text-black font-black uppercase tracking-widest flex items-center justify-center gap-2">
                           {isLoading ? <Loader2 className="animate-spin" /> : <><CheckCircle size={18} /> Save</>}
                        </button>
                      </>
                   ) : (
                      <button onClick={capturePhoto} className="w-full py-4 bg-white text-black font-black uppercase tracking-widest rounded-2xl flex items-center justify-center gap-2 shadow-xl hover:scale-105 transition-transform">
                          <Camera size={20} /> Capture
                      </button>
                   )}
                </div>
                <button onClick={handleSkipAvatar} className="text-gray-500 text-xs font-bold uppercase tracking-widest hover:text-white transition-colors">
                   Skip Initialization <ChevronRight size={10} className="inline" />
                </button>
             </div>
          </motion.div>
        )}
      </AnimatePresence>

      {!showCamera && (
        <div className="relative z-10 min-h-screen w-full flex flex-col items-center justify-center p-6 py-12 lg:py-24">
          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="w-full max-w-md glass-panel rounded-[3rem] p-8 md:p-12 border border-white/10 shadow-2xl my-auto"
          >
            <div className="flex flex-col items-center mb-10 text-center">
              <Logo className="h-[120px] w-auto mb-6" />
              <p className="text-[10px] text-gray-500 font-black uppercase tracking-[0.4em]">Elite Fitness Ecosystem</p>
            </div>

            <AnimatePresence>
              {error && (
                <motion.div 
                  initial={{ height: 0, opacity: 0, scale: 0.95 }} 
                  animate={{ height: 'auto', opacity: 1, scale: 1 }} 
                  exit={{ height: 0, opacity: 0, scale: 0.95 }}
                  className="bg-red-500/10 border border-red-500/20 rounded-2xl p-5 mb-6 flex flex-col gap-2 text-red-400 shadow-lg"
                >
                  <div className="flex items-center gap-3 text-xs font-bold">
                    {lockoutTimer > 0 ? <Clock size={16} className="shrink-0" /> : <AlertCircle size={16} className="shrink-0" />} 
                    <span className="flex-1">{lockoutTimer > 0 ? "System Lockout Active" : "Authentication Error"}</span>
                  </div>
                  <p className="text-[11px] leading-relaxed text-red-300/80 italic pl-7 font-medium">
                    {error}
                  </p>
                </motion.div>
              )}
            </AnimatePresence>

            <form onSubmit={handleAuth} className="space-y-4">
              {!isLogin && (
                 <div className="relative group">
                    <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-500" />
                    <input type="text" value={name} onChange={(e) => setName(e.target.value)} placeholder="Full Name"
                      className="w-full pl-12 pr-4 py-4 bg-white/5 border border-white/10 rounded-xl text-white outline-none focus:border-luxury-neon transition-all" />
                 </div>
              )}
              <div className="relative group">
                 <Mail className="absolute left-4 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-500" />
                 <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="Enter your email"
                   className="w-full pl-12 pr-4 py-4 bg-white/5 border border-white/10 rounded-xl text-white outline-none focus:border-luxury-neon transition-all" />
              </div>
              <div className="relative group">
                 <Lock className="absolute left-4 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-500" />
                 <input type={showPassword ? "text" : "password"} value={password} onChange={(e) => setPassword(e.target.value)} placeholder="Enter your password"
                   className="w-full pl-12 pr-12 py-4 bg-white/5 border border-white/10 rounded-xl text-white outline-none focus:border-luxury-neon transition-all" />
                 <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-500 hover:text-white transition-colors">
                    {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                 </button>
              </div>

              <div className="flex items-center gap-2 cursor-pointer w-fit" onClick={() => setRememberMe(!rememberMe)}>
                 <div className={`w-4 h-4 border border-white/30 rounded flex items-center justify-center transition-colors ${rememberMe ? 'bg-luxury-neon border-luxury-neon' : 'bg-transparent'}`}>
                    {rememberMe && <Check size={12} className="text-black" />} 
                 </div>
                 <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest select-none">Remember Me</span>
              </div>

              {isLogin && (
                 <div className="flex justify-end items-center text-[10px] font-black tracking-widest uppercase mt-2">
                    <button type="button" onClick={() => setIsResetModalOpen(true)} className="text-luxury-neon">Forgot Credentials?</button>
                 </div>
              )}

              {!isLogin && (
                 <input type="password" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} placeholder="Confirm Password"
                   className="w-full pl-12 pr-4 py-4 bg-white/5 border border-white/10 rounded-xl text-white outline-none focus:border-luxury-neon transition-all" />
              )}

              <button 
                disabled={isLoading || lockoutTimer > 0} 
                className="w-full py-4 bg-luxury-neon text-black font-black uppercase tracking-widest text-sm rounded-xl shadow-lg shadow-luxury-neon/20 disabled:opacity-50 mt-4 hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center justify-center gap-2"
              >
                 {isLoading ? (
                    <Loader2 className="animate-spin" size={20} />
                 ) : lockoutTimer > 0 ? (
                    <>Throttled: Retry in {lockoutTimer}s</>
                 ) : (
                    isLogin ? "Authenticate" : "Create Account"
                 )}
              </button>
            </form>

            <div className="flex flex-col gap-4 mt-6">
               <button 
                  onClick={handleGuestMode}
                  disabled={isLoading || lockoutTimer > 0}
                  className="w-full py-3 bg-white/5 border border-white/10 text-gray-400 font-bold uppercase tracking-widest text-[10px] rounded-xl flex items-center justify-center gap-2 hover:bg-white/10 hover:text-white transition-all disabled:opacity-50"
               >
                  {isLoading ? <Loader2 size={16} className="animate-spin" /> : <><UserCircle2 size={16} /> Continue as Guest</>}
               </button>
            </div>

            <div className="mt-8 pt-6 border-t border-white/5 text-center">
              <button onClick={() => { setIsLogin(!isLogin); setError(null); }} className="text-sm font-bold text-gray-400 hover:text-white transition-colors">
                 {isLogin ? "New to the hub?" : "Already a member?"} <span className="text-luxury-neon ml-1">Swap Protocol</span>
              </button>
            </div>

            <div className="h-20 md:h-0" />
          </motion.div>
        </div>
      )}

      <AnimatePresence>
        {isResetModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-6">
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={() => setIsResetModalOpen(false)} className="absolute inset-0 bg-black/90 backdrop-blur-sm" />
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }} className="relative w-full max-w-sm glass-panel p-8 rounded-3xl border border-white/10">
               <h2 className="text-xl font-black text-white uppercase tracking-widest mb-4">Reset Access</h2>
               <p className="text-xs text-gray-400 mb-6 leading-relaxed">Enter your registered email to receive recovery instructions.</p>

               <input 
                  type="email" 
                  value={resetEmail} 
                  onChange={(e) => setResetEmail(e.target.value)} 
                  placeholder="Email Address" 
                  className="w-full bg-white/5 border border-white/10 rounded-xl p-4 text-white outline-none mb-4 focus:border-luxury-neon transition-all" 
               />
               <button onClick={handleResetPassword} className="w-full py-4 bg-white text-black font-black uppercase text-xs tracking-widest rounded-xl hover:bg-gray-200 transition-colors">Send Recovery Link</button>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

