import React, { ErrorInfo, ReactNode } from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';
import { Activity } from 'lucide-react';

// --- AGGRESSIVE STORAGE CLEANUP ---
/**
 * Automatically prunes localStorage to prevent QuotaExceededError.
 * Keeps only essential Supabase auth tokens and the remembered email.
 */
const cleanupStorage = () => {
  try {
    const keysToKeep = [
      'healthy_hub_remembered_email', 
      'sb-tngzcpgoshpfwuarskul-auth-token' // Specific Supabase token prefix
    ];

    const keys = Object.keys(localStorage);
    keys.forEach(key => {
      // Keep Supabase internal keys and our remembered email
      if (key.startsWith('sb-') || keysToKeep.includes(key)) {
        return;
      }

      // Wipe everything else if it exists
      localStorage.removeItem(key);
      console.log(`[Storage Recovery] Purged: ${key}`);
    });
  } catch (e) {
    console.warn("Storage cleanup failed", e);
  }
};

// Execute immediately on load
cleanupStorage();

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  public state: ErrorBoundaryState = {
    hasError: false,
    error: null
  };

  constructor(props: ErrorBoundaryProps) {
    super(props);
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught Error:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="h-screen w-screen bg-black text-white flex flex-col items-center justify-center p-6 text-center font-sans">
          <div className="mb-6 opacity-30">
            <Activity size={48} color="#CEF245" />
          </div>
          <h1 className="text-xl font-black mb-3 tracking-[0.2em] text-luxury-neon uppercase">Recovery Protocol</h1>
          <p className="text-gray-500 max-w-xs text-xs leading-relaxed mb-8">
             The system encountered an unexpected anomaly. Data integrity remains intact.
          </p>
          <button 
            onClick={() => {
                localStorage.clear(); // Nuclear reset on error
                window.location.reload();
            }}
            className="px-8 py-4 bg-white/5 text-white border border-white/10 rounded-full font-bold text-[10px] tracking-[0.2em] uppercase active:scale-95 transition-all"
          >
            Reset & Reboot System
          </button>
        </div>
      );
    }

    return (this as any).props.children;
  }
}

const lockOrientation = async () => {
  const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
  if (isMobile && screen.orientation && typeof (screen.orientation as any).lock === 'function') {
    try {
      await (screen.orientation as any).lock('portrait');
    } catch (e) {}
  }
};

lockOrientation().catch(() => {});

const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(
    <ErrorBoundary>
      <App />
    </ErrorBoundary>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  createUserDocument, 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  updateProfile,
  sendPasswordResetEmail,
  signInAsGuest,
  User
} from '../services/supabase'; 
import { Loader2, Eye, EyeOff, AlertCircle, User as UserIcon, Mail, Lock, CheckCircle, Camera, RefreshCw, ChevronRight, UserCircle2, Check, ArrowRight, Clock, DatabaseZap } from 'lucide-react';
import Logo from './Logo';

interface AuthProps {
  onLoginSuccess: () => void;
}

const Auth: React.FC<AuthProps> = ({ onLoginSuccess }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);
  const [quotaError, setQuotaError] = useState(false);

  // Cooldown State
  const [lockoutTimer, setLockoutTimer] = useState(0);

  // Remember Me State
  const [rememberMe, setRememberMe] = useState(false);

  // Avatar Capture State
  const [showCamera, setShowCamera] = useState(false);
  const [tempUser, setTempUser] = useState<User | null>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const [isResetModalOpen, setIsResetModalOpen] = useState(false);
  const [resetEmail, setResetEmail] = useState('');
  const [resetError, setResetError] = useState<string | null>(null);
  const [resetSuccess, setResetSuccess] = useState<string | null>(null);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  // --- INIT: CHECK LOCAL STORAGE & COOLDOWN ---
  useEffect(() => {
    const savedEmail = localStorage.getItem('healthy_hub_remembered_email');
    if (savedEmail) {
      setEmail(savedEmail);
      setRememberMe(true);
    }
  }, []);

  useEffect(() => {
    let interval: number;
    if (lockoutTimer > 0) {
      interval = window.setInterval(() => {
        setLockoutTimer((prev) => prev - 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [lockoutTimer]);

  const nuclearReset = () => {
    const savedEmail = localStorage.getItem('healthy_hub_remembered_email');
    localStorage.clear();
    if (savedEmail) localStorage.setItem('healthy_hub_remembered_email', savedEmail);
    window.location.reload();
  };

  // --- CAMERA FUNCTIONS ---
  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'user', width: { ideal: 500 }, height: { ideal: 500 } }
      });
      setStream(mediaStream);
      setTimeout(() => {
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
          videoRef.current.play().catch(e => console.error("Video play failed", e));
        }
      }, 100);
    } catch (err) {
      setError("Could not access camera for profile photo.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(t => t.stop());
      setStream(null);
    }
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const size = Math.min(video.videoWidth, video.videoHeight);
      canvas.width = size;
      canvas.height = size;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        const startX = (video.videoWidth - size) / 2;
        const startY = (video.videoHeight - size) / 2;
        ctx.drawImage(video, startX, startY, size, size, 0, 0, size, size);
        const base64 = canvas.toDataURL('image/jpeg', 0.8);
        setCapturedImage(base64);
        stopCamera();
      }
    }
  };

  const handleRetake = () => {
    setCapturedImage(null);
    startCamera();
  };

  const handleSaveAvatar = async () => {
    if (!capturedImage || !tempUser) return;
    setIsLoading(true);
    try {
      await updateProfile(tempUser, { photoURL: capturedImage });
      onLoginSuccess();
    } catch (e) {
      setError("Failed to save profile photo.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleSkipAvatar = () => {
    stopCamera();
    onLoginSuccess();
  };

  const handleGuestMode = () => {
    setIsLoading(true);
    signInAsGuest();
  };

  // --- AUTH LOGIC ---
  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    if (lockoutTimer > 0) return;

    setError(null);
    setQuotaError(false);
    setSuccessMsg(null);
    setIsLoading(true);

    const performAuth = async () => {
      if (isLogin) {
        const data = await signInWithEmailAndPassword(email, password);
        if (rememberMe) {
          localStorage.setItem('healthy_hub_remembered_email', email);
        } else {
          localStorage.removeItem('healthy_hub_remembered_email');
        }
        onLoginSuccess();
      } else {
        if (password !== confirmPassword) throw new Error("Passwords do not match.");
        if (password.length < 6) throw new Error("Password must be at least 6 characters.");
        const { data } = await createUserWithEmailAndPassword(email, password);
        if (rememberMe) {
          localStorage.setItem('healthy_hub_remembered_email', email);
        } else {
          localStorage.removeItem('healthy_hub_remembered_email');
        }
        const user = data.user;
        if (user) {
            if (name) {
                await updateProfile(user, { displayName: name });
                await createUserDocument(user, name);
            } else {
                await createUserDocument(user, 'Elite User');
            }
            setTempUser(user);
            setShowCamera(true);
            startCamera();
        }
      }
    };

    try {
      await performAuth();
    } catch (err: any) {
      console.error('❌ AUTH ERROR:', err);

      // AGGRESSIVE QUOTA RECOVERY
      if (err.message?.toLowerCase().includes('quota') || err.name === 'QuotaExceededError') {
        console.warn("Storage Quota hit. Attempting nuclear clear...");
        setQuotaError(true);

        // Try clearing EVERYTHING except the token we are trying to set
        const keys = Object.keys(localStorage);
        keys.forEach(k => {
            if (!k.startsWith('sb-')) localStorage.removeItem(k);
        });

        try {
          await performAuth();
          setQuotaError(false);
          return;
        } catch (retryErr: any) {
          setError("Device storage is completely full. Use the Reset button below to wipe all local data.");
          setIsLoading(false);
          return;
        }
      }

      let msg = err.message || "Authentication failed.";
      const lowerMsg = msg.toLowerCase();

      if (lowerMsg.includes("rate limit") || lowerMsg.includes("too many requests") || lowerMsg.includes("throttled")) {
        msg = "Too many attempts. Authentication throttled. Please wait 60 seconds.";
        setLockoutTimer(60);
      } else if (lowerMsg.includes("invalid login credentials") || lowerMsg.includes("user not found")) {
        msg = "Account not found. Verify your credentials or Sign Up.";
      } else if (lowerMsg.includes("email already in use")) {
        msg = "This email is already registered. Try logging in.";
      }

      setError(msg);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="h-screen w-full flex flex-col bg-black font-sans relative overflow-y-auto no-scrollbar scroll-smooth">
