// --- AGGRESSIVE STORAGE CLEANUP ---
/**
 * Automatically prunes localStorage to prevent QuotaExceededError.
 * Keeps only essential Supabase auth tokens and the remembered email.
 */
const cleanupStorage = () => {
  try {
    const keysToKeep = [
      'healthy_hub_remembered_email', 
    ];

    const keys = Object.keys(localStorage);
    console.log(`[Storage Diagnostic] Found ${keys.length} keys in localStorage.`);

    keys.forEach(key => {
      // Keep Supabase internal keys and our remembered email
      // Supabase keys typically start with 'sb-'
      if (key.startsWith('sb-') || keysToKeep.includes(key)) {
        return;
      }

      // Wipe everything else immediately on load
      localStorage.removeItem(key);
      console.log(`[Storage Recovery] Purged: ${key}`);
    });
  } catch (e) {
    console.warn("Storage cleanup failed", e);
  }
};

// Execute immediately on load to ensure maximum space for Auth
cleanupStorage();

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  public state: ErrorBoundaryState = {
    hasError: false,
    error: null
  };

  constructor(props: ErrorBoundaryProps) {
    super(props);
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught Error:", error, errorInfo);
    // If we catch a generic error, it might be storage related too
    if (error.name === 'QuotaExceededError') {
      localStorage.clear();
      window.location.reload();
    }
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="h-screen w-screen bg-black text-white flex flex-col items-center justify-center p-6 text-center font-sans">
          <div className="mb-6 opacity-30">
            <Activity size={48} color="#CEF245" />
          </div>
          <h1 className="text-xl font-black mb-3 tracking-[0.2em] text-luxury-neon uppercase">Recovery Protocol</h1>
          <p className="text-gray-500 max-w-xs text-xs leading-relaxed mb-8">
             The system encountered an unexpected anomaly. This is usually due to full device storage.
          </p>
          <button 
            onClick={() => {
                localStorage.clear(); // Nuclear reset on error
                window.location.reload();
            }}
            className="px-8 py-4 bg-white/5 text-white border border-white/10 rounded-full font-bold text-[10px] tracking-[0.2em] uppercase active:scale-95 transition-all"
          >
            Clear & Reboot System
          </button>
        </div>
      );
    }

    return (this as any).props.children;
  }
}

const lockOrientation = async () => {
  const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
  if (isMobile && screen.orientation && typeof (screen.orientation as any).lock === 'function') {
    try {
      await (screen.orientation as any).lock('portrait');
    } catch (e) {}
  }
};

lockOrientation().catch(() => {});

const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(
    <ErrorBoundary>
      <App />
    </ErrorBoundary>
  );
}

import React, { useState, useEffect } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import { 
  onAuthStateChanged,
  User,
  fetchFullUserDashboard,
  syncDailyActivity
} from './services/supabase';

import Navigation from './components/Navigation';
import Dashboard from './components/Dashboard';
import FoodLens from './components/FoodLens';
import BMIHub from './components/BMIHub';
import MapTrackingScreen from './components/MapTrackingScreen';
import ChatBot from './components/ChatBot';
import ProfileScreen from './components/ProfileScreen';
import OnboardingScreen from './components/OnboardingScreen'; 
import WorkoutLab from './components/WorkoutLab';
import Auth from './components/Auth';
import { ViewState, ActivityData, FoodHistoryItem, UserMetrics } from './types';
import useLocalStorage from './hooks/useLocalStorage';
import usePedometer from './hooks/usePedometer';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [userProfile, setUserProfile] = useState<any>(null);
  const [isAuthChecking, setIsAuthChecking] = useState(true); 
  const [isProfileChecking, setIsProfileChecking] = useState(false);

  const [isInitialLoadComplete, setIsInitialLoadComplete] = useState(false);

  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);
  const { isTracking, toggleTracking, liveSteps, resetLiveSteps } = usePedometer();

  const [activityData, setActivityData] = useState<ActivityData>({
    steps: 0, calories: 0, distance: 0, stepGoal: 10000, calorieGoal: 2000, distanceGoal: 5.0, history: []
  });

  const [bmiMetrics, setBmiMetrics] = useLocalStorage<UserMetrics>('bmi_metrics', { height: 175, weight: 70 });

  // DRATICALLY reduced history to 5 items to save space for critical Auth tokens
  const [foodHistory, setFoodHistory] = useLocalStorage<FoodHistoryItem[]>('food_history', []);
  const [adaptiveGoalsEnabled, setAdaptiveGoalsEnabled] = useLocalStorage<boolean>('adaptive_goals_enabled', true);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(async (user) => {
      setIsInitialLoadComplete(false);

      if (user) {
        setCurrentUser(user);
        setIsProfileChecking(true);

        try {
          const dashboardData = await fetchFullUserDashboard(user.id);

          if (dashboardData) {
              if (dashboardData.profile) setUserProfile(dashboardData.profile);

              setActivityData(prev => ({
                ...prev,
                steps: dashboardData.todayActivity?.steps || 0,
                calories: dashboardData.todayActivity?.calories_burned || 0,
                stepGoal: dashboardData.profile?.goals?.stepGoal || prev.stepGoal,
                calorieGoal: dashboardData.profile?.goals?.calorieGoal || prev.calorieGoal
              }));
          }
        } catch (e) {
          console.error("Critical Profile Load Failure:", e);
        } finally {
          setIsInitialLoadComplete(true);
          setIsProfileChecking(false);
        }
      } else { 
        setCurrentUser(null); 
        setUserProfile(null);
        setIsInitialLoadComplete(false);
      }
      setIsAuthChecking(false);
    });
    return () => { if (unsubscribe) unsubscribe(); };
  }, []);

  useEffect(() => {
    if (!currentUser || !isInitialLoadComplete) return;

    if (liveSteps > 0) {
       setActivityData(prev => {
          const newSteps = prev.steps + liveSteps;
          const newCals = prev.calories + (liveSteps * 0.04);
          syncDailyActivity(currentUser.id, newSteps, Math.floor(newCals), prev.stepGoal);
          return { ...prev, steps: newSteps, calories: newCals };
       });
       resetLiveSteps();
    }
  }, [liveSteps, currentUser, isInitialLoadComplete, resetLiveSteps]);

  const handleUpdateGoals = (newGoals: Partial<ActivityData>) => setActivityData(prev => ({ ...prev, ...newGoals }));

  const handleAddToFoodHistory = (item: FoodHistoryItem) => {
    setFoodHistory(prev => {
      // Limit to last 5 items to protect localStorage quota
      const newHistory = [item, ...prev].slice(0, 5);
      return newHistory;
    });
  };

  if (isAuthChecking) return <div className="h-screen bg-black flex items-center justify-center text-luxury-neon animate-pulse text-[10px] uppercase tracking-[0.3em]">Initialising Ecosystem...</div>;
  if (!currentUser) return <Auth onLoginSuccess={() => {}} />;
  if (isProfileChecking) return <div className="h-screen bg-black flex items-center justify-center text-gray-400 text-[10px] uppercase tracking-[0.3em]">Synchronizing Records...</div>;

  if (!userProfile) {
     return <OnboardingScreen user={currentUser} onComplete={(p) => { setUserProfile(p); setCurrentView(ViewState.DASHBOARD); }} />;
  }

  const pageTransition = {
    initial: { opacity: 0, x: 20 },
    animate: { opacity: 1, x: 0 },
    exit: { opacity: 0, x: -20 },
    transition: { type: 'spring', damping: 25, stiffness: 200 }
  };

  return (
    <div className="flex flex-col h-[100dvh] bg-black text-white relative overflow-hidden font-sans">
      <main className="flex-1 relative w-full overflow-hidden">
        <AnimatePresence mode="wait">
          {currentView === ViewState.DASHBOARD && (
            <motion.div key="dash" {...pageTransition} className="h-full w-full">
              <Dashboard 
                data={activityData} 
                onUpdateGoals={handleUpdateGoals} 
                isTracking={isTracking} 
                onToggleTracking={toggleTracking} 
                foodHistory={foodHistory}
                adaptiveGoalsEnabled={adaptiveGoalsEnabled}
                onToggleAdaptiveGoals={setAdaptiveGoalsEnabled}
              />
            </motion.div>
          )}
          {currentView === ViewState.CHAT && (
            <motion.div key="chat" {...pageTransition} className="h-full w-full">
              <ChatBot metrics={bmiMetrics} activity={activityData} onUpdateTargets={(c, s, p) => {
                setActivityData(prev => ({ ...prev, calorieGoal: c, stepGoal: s }));
              }} />
            </motion.div>
          )}
          {currentView === ViewState.FOOD_LENS && (
            <motion.div key="lens" {...pageTransition} className="h-full w-full">
              <FoodLens history={foodHistory} onAddToHistory={handleAddToFoodHistory} />
            </motion.div>
          )}
          {currentView === ViewState.BMI_HUB && (
            <motion.div key="bmi" {...pageTransition} className="h-full w-full">
              <BMIHub />
            </motion.div>
          )}
          {currentView === ViewState.MAP_TRACKER && (
            <motion.div key="map" {...pageTransition} className="h-full w-full">
              <MapTrackingScreen userHeight={bmiMetrics.height} />
            </motion.div>
          )}
          {currentView === ViewState.PROFILE && (
            <motion.div key="profile" {...pageTransition} className="h-full w-full">
              <ProfileScreen onUpdateMetrics={setBmiMetrics} />
            </motion.div>
          )}
          {currentView === ViewState.WORKOUT_LAB && (
            <motion.div key="lab" {...pageTransition} className="h-full w-full">
              <WorkoutLab metrics={bmiMetrics} />
            </motion.div>
          )}
        </AnimatePresence>
      </main>
      <Navigation currentView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  createUserDocument, 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  updateProfile,
  sendPasswordResetEmail,
  signInAsGuest,
  User
} from '../services/supabase'; 
import { Loader2, Eye, EyeOff, AlertCircle, User as UserIcon, Mail, Lock, CheckCircle, Camera, RefreshCw, ChevronRight, UserCircle2, Check, ArrowRight, Clock, DatabaseZap } from 'lucide-react';
import Logo from './Logo';

interface AuthProps {
  onLoginSuccess: () => void;
}

const Auth: React.FC<AuthProps> = ({ onLoginSuccess }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);
  const [quotaError, setQuotaError] = useState(false);

  // Cooldown State
  const [lockoutTimer, setLockoutTimer] = useState(0);

  // Remember Me State
  const [rememberMe, setRememberMe] = useState(false);

  // Avatar Capture State
  const [showCamera, setShowCamera] = useState(false);
  const [tempUser, setTempUser] = useState<User | null>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);
  videoRef = useRef<HTMLVideoElement>(null);
  canvasRef = useRef<HTMLCanvasElement>(null);

  const [isResetModalOpen, setIsResetModalOpen] = useState(false);
  const [resetEmail, setResetEmail] = useState('');
  const [resetError, setResetError] = useState<string | null>(null);
  const [resetSuccess, setResetSuccess] = useState<string | null>(null);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  // --- INIT: CHECK LOCAL STORAGE & COOLDOWN ---
  useEffect(() => {
    const savedEmail = localStorage.getItem('healthy_hub_remembered_email');
    if (savedEmail) {
      setEmail(savedEmail);
      setRememberMe(true);
    }
  }, []);

  useEffect(() => {
    let interval: number;
    if (lockoutTimer > 0) {
      interval = window.setInterval(() => {
        setLockoutTimer((prev) => prev - 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [lockoutTimer]);

  const nuclearReset = () => {
    console.warn("[Storage] Nuclear reset triggered by user.");
    localStorage.clear();
    window.location.reload();
  };

  // --- CAMERA FUNCTIONS ---
  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'user', width: { ideal: 500 }, height: { ideal: 500 } }
      });
      setStream(mediaStream);
      setTimeout(() => {
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
          videoRef.current.play().catch(e => console.error("Video play failed", e));
        }
      }, 100);
    } catch (err) {
      setError("Could not access camera for profile photo.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(t => t.stop());
      setStream(null);
    }
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const size = Math.min(video.videoWidth, video.videoHeight);
      canvas.width = size;
      canvas.height = size;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        const startX = (video.videoWidth - size) / 2;
        const startY = (video.videoHeight - size) / 2;
        ctx.drawImage(video, startX, startY, size, size, 0, 0, size, size);
        const base64 = canvas.toDataURL('image/jpeg', 0.8);
        setCapturedImage(base64);
        stopCamera();
      }
    }
  };

  const handleRetake = () => {
    setCapturedImage(null);
    startCamera();
  };

  const handleSaveAvatar = async () => {
    if (!capturedImage || !tempUser) return;
    setIsLoading(true);
    try {
      await updateProfile(tempUser, { photoURL: capturedImage });
      onLoginSuccess();
    } catch (e) {
      setError("Failed to save profile photo.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleSkipAvatar = () => {
    stopCamera();
    onLoginSuccess();
  };

  const handleGuestMode = () => {
    setIsLoading(true);
    signInAsGuest();
  };

  // --- PASSWORD RESET ---
  const handleResetPassword = async () => {
    if (!resetEmail) {
      setResetError("Email required for protocol recovery.");
      return;
    }
    setIsLoading(true);
    setResetError(null);
    setResetSuccess(null);
    try {
      await sendPasswordResetEmail(resetEmail);
      setResetSuccess("Recovery instructions dispatched.");
      setTimeout(() => {
        setIsResetModalOpen(false);
        setResetSuccess(null);
        setResetEmail('');
      }, 2500);
    } catch (err: any) {
      setResetError(err.message || "Failed to initiate recovery.");
    } finally {
      setIsLoading(false);
    }
  };

  // --- AUTH LOGIC ---
  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    if (lockoutTimer > 0) return;

    setError(null);
    setQuotaError(false);
    setSuccessMsg(null);
    setIsLoading(true);

    const performAuth = async () => {
      if (isLogin) {
        const data = await signInWithEmailAndPassword(email, password);
        if (rememberMe) {
          localStorage.setItem('healthy_hub_remembered_email', email);
        } else {
          localStorage.removeItem('healthy_hub_remembered_email');
        }
        onLoginSuccess();
      } else {
        if (password !== confirmPassword) throw new Error("Passwords do not match.");
        if (password.length < 6) throw new Error("Password must be at least 6 characters.");
        const { data } = await createUserWithEmailAndPassword(email, password);
        if (rememberMe) {
          localStorage.setItem('healthy_hub_remembered_email', email);
        } else {
          localStorage.removeItem('healthy_hub_remembered_email');
        }
        const user = data.user;
        if (user) {
            if (name) {
                await updateProfile(user, { displayName: name });
                await createUserDocument(user, name);
            } else {
                await createUserDocument(user, 'Elite User');
            }
            setTempUser(user);
            setShowCamera(true);
            startCamera();
        }
      }
    };

    try {
      await performAuth();
    } catch (err: any) {
      console.error('❌ AUTH ERROR:', err);

      // CRITICAL QUOTA HANDLING
      if (err.message?.toLowerCase().includes('quota') || err.name === 'QuotaExceededError') {
        console.warn("Storage Quota hit during Auth. Executing Emergency Wipe...");
        setQuotaError(true);

        // Immediate wipe of everything non-essential to make room for token
        localStorage.clear();
        if (email) localStorage.setItem('healthy_hub_remembered_email', email);

        try {
          // Retry one last time after complete wipe
          await performAuth();
          setQuotaError(false);
          return;
        } catch (retryErr: any) {
          setError("Device storage is completely exhausted. Authentication tokens cannot be saved. Please clear browser data.");
          setIsLoading(false);
          return;
        }
      }

      let msg = err.message || "Authentication failed.";
      const lowerMsg = msg.toLowerCase();

      if (lowerMsg.includes("rate limit") || lowerMsg.includes("too many requests") || lowerMsg.includes("throttled")) {
        msg = "Too many attempts. Authentication throttled. Please wait 60 seconds.";
        setLockoutTimer(60);
      } else if (lowerMsg.includes("invalid login credentials") || lowerMsg.includes("user not found")) {
        msg = "Account not found. Verify your credentials or Sign Up.";
      } else if (lowerMsg.includes("email already in use")) {
        msg = "This email is already registered. Try logging in.";
      }

      setError(msg);
    } finally {
      setIsLoading(false);
    }
  };

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  return (
    <div className="h-screen w-full flex flex-col bg-black font-sans relative overflow-y-auto no-scrollbar scroll-smooth">
      <div className="fixed inset-0 z-0 bg-cover bg-center grayscale blur-md opacity-40 scale-105 pointer-events-none"
        style={{ backgroundImage: 'url("https://images.unsplash.com/photo-1534438327276-14e5300c3a48?q=80&w=2070&auto=format&fit=crop")' }} />
      <div className="fixed inset-0 z-0 bg-gradient-to-b from-black/80 via-black/90 to-black pointer-events-none"></div>

      <AnimatePresence>
        {showCamera && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
