        const { data } = await createUserWithEmailAndPassword(email, password);
        if (rememberMe) {
          localStorage.setItem('healthy_hub_remembered_email', email);
        } else {
          localStorage.removeItem('healthy_hub_remembered_email');
        }
        const user = data.user;
        if (user) {
            if (name) {
                await updateProfile(user, { displayName: name });
                await createUserDocument(user, name);
            } else {
                await createUserDocument(user, 'Elite User');
            }
            setTempUser(user);
            setShowCamera(true);
            startCamera();
        }
      }
    };

    try {
      await performAuth();
    } catch (err: any) {
      console.error('❌ AUTH ERROR:', err);

      // CRITICAL QUOTA HANDLING
      if (err.message?.toLowerCase().includes('quota') || err.name === 'QuotaExceededError') {
        console.warn("Storage Quota hit during Auth. Executing Emergency Wipe...");
        setQuotaError(true);

        // Immediate wipe of everything non-essential to make room for token
        localStorage.clear();
        if (email) localStorage.setItem('healthy_hub_remembered_email', email);

        try {
          // Retry one last time after complete wipe
          await performAuth();
          setQuotaError(false);
