// --- STRETCH STORAGE PROTOCOL ---
/**
 * Destructively prunes localStorage to prevent QuotaExceededError.
 * Prioritizes space for the specific project: tngzcpgoshpfwuarskul
 */
const cleanupStorage = () => {
  try {
    const CURRENT_PROJECT_ID = 'tngzcpgoshpfwuarskul';
    const keysToKeep = [
      'healthy_hub_remembered_email',
      `sb-${CURRENT_PROJECT_ID}-auth-token`
    ];

    const keys = Object.keys(localStorage);

    keys.forEach(key => {
      // Only keep the essential keys for THIS specific project
      if (keysToKeep.includes(key)) {
        return;
      }

      // Wipe everything else (including other Supabase project tokens or large app data)
      localStorage.removeItem(key);
    });

    console.log(`[Storage Protocol] Optimized. Total keys: ${Object.keys(localStorage).length}`);
  } catch (e) {
    // If cleanup fails, the storage is likely in a corrupted state
    console.warn("Storage cleanup failed. Resetting...", e);
    localStorage.clear();
  }
};

// Execute immediately on load to ensure maximum space for Auth
cleanupStorage();

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  public state: ErrorBoundaryState = {
    hasError: false,
    error: null
  };

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught Error:", error, errorInfo);
    // Automatic recovery for storage errors
    if (error.name === 'QuotaExceededError' || error.message.includes('quota')) {
      localStorage.clear();
      window.location.reload();
    }
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="h-screen w-screen bg-black text-white flex flex-col items-center justify-center p-6 text-center font-sans">
          <div className="mb-6 opacity-30">
            <Activity size={48} color="#CEF245" />
          </div>
          <h1 className="text-xl font-black mb-3 tracking-[0.2em] text-luxury-neon uppercase">Recovery Protocol</h1>
          <p className="text-gray-500 max-w-xs text-xs leading-relaxed mb-8">
             The system storage is exhausted. Clearing local data to restore access.
          </p>
          <button 
            onClick={() => {
                localStorage.clear();
                window.location.reload();
            }}
            className="px-8 py-4 bg-white/5 text-white border border-white/10 rounded-full font-bold text-[10px] tracking-[0.2em] uppercase active:scale-95 transition-all"
          >
            Clear & Reset Ecosystem
          </button>
        </div>
      );
    }

    return (this as any).props.children;
  }
}

const lockOrientation = async () => {
  const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
  if (isMobile && screen.orientation && typeof (screen.orientation as any).lock === 'function') {
    try {
      await (screen.orientation as any).lock('portrait');
    } catch (e) {}
  }
};

lockOrientation().catch(() => {});

const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(
    <ErrorBoundary>
      <App />
    </ErrorBoundary>
  );
}

