                  className="bg-red-500/10 border border-red-500/20 rounded-2xl p-5 mb-6 flex flex-col gap-3 text-red-400 shadow-lg overflow-hidden"
                >
                  <div className="flex items-center gap-3 text-xs font-bold">
                    <AlertCircle size={16} className="shrink-0" /> 
                    <span className="flex-1">{isCredentialError ? "Auth Protocol Refused" : "System Error"}</span>
