                  className="w-full bg-white/5 border border-white/10 rounded-xl p-4 text-white outline-none mb-4 focus:border-luxury-neon transition-all" 
               />
               <button 
                onClick={handleResetPassword} 
                disabled={isLoading}
                className="w-full py-4 bg-white text-black font-black uppercase text-xs tracking-widest rounded-xl hover:bg-gray-200 transition-colors disabled:opacity-50"
               >
                {isLoading ? <Loader2 className="animate-spin mx-auto" size={16} /> : "Send Recovery Link"}
               </button>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

