                 </div>
              )}
              <div className="relative group">
                 <Mail className="absolute left-4 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-500" />
                 <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="Elite Email"
