import { ActivityData, UserMetrics, UserProfile, DailyActivityDB, FoodLogDB, ChatHistoryDB, SavedWorkoutDB, WorkoutPlan } from '../types';

export type { User } from '@supabase/supabase-js';

const SUPABASE_URL = 'https://tngzcpgoshpfwuarskul.supabase.co';
const SUPABASE_ANON_KEY = 'sb_publishable_OyoWs8f9j8fNI9Y4YbPilg_tFtAQUNX';
const PROJECT_ID = 'tngzcpgoshpfwuarskul';

/**
 * NUCLEAR STORAGE PROTOCOL
 * Aggressively clears non-essential localStorage to ensure Supabase auth tokens can be saved.
 */
export const performMaintenance = () => {
  try {
    const currentAuthKey = `sb-${PROJECT_ID}-auth-token`;

    // 1. Identify all keys
    const keys = Object.keys(localStorage);

    // 2. IMMEDIATE: Clear tokens from OTHER project IDs
    keys.forEach(key => {
      if (key.startsWith('sb-') && !key.includes(PROJECT_ID)) {
        localStorage.removeItem(key);
      }
    });

    // 3. Check total size and prune non-essential caches if over 1MB
    let totalSize = 0;
    for (const key of Object.keys(localStorage)) {
      totalSize += (localStorage.getItem(key)?.length || 0) * 2;
    }

    if (totalSize > 1 * 1024 * 1024) { 
      console.warn("[Storage] Quota pressure detected. Pruning non-essential caches.");
      localStorage.removeItem('food_history');
      localStorage.removeItem('chat_history');
      localStorage.removeItem('workout_lab_cache');
      localStorage.removeItem('sb-tngzcpgoshpfwuarskul-auth-token-code-verifier');
    }
  } catch (e) {
    console.error("[Storage] Maintenance protocol failed:", e);
  }
};

/**
 * Custom storage adapter to handle QuotaExceededError within the Supabase SDK.
 */
const adaptiveStorage: SupportedStorage = {
  getItem: (key) => {
    try {
      return localStorage.getItem(key);
    } catch (e) {
      return null;
    }
  },
  setItem: (key, value) => {
    try {
      localStorage.setItem(key, value);
    } catch (e: any) {
      // If quota exceeded, perform emergency maintenance and retry once
      if (e.name === 'QuotaExceededError' || e.message.includes('quota')) {
        console.error("[Storage] Quota Exceeded during setItem. Triggering emergency purge.");
        performMaintenance();
        try {
          localStorage.setItem(key, value);
        } catch (retryError) {
          console.error("[Storage] Critical: Storage completely exhausted. Persistent auth may fail.");
        }
      }
    }
  },
  removeItem: (key) => {
    try {
      localStorage.removeItem(key);
    } catch (e) {}
  }
};

// Execute maintenance before client initialization
performMaintenance();

export const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY, {
  auth: {
    detectSessionInUrl: false,
    persistSession: true,
    autoRefreshToken: true,
    storageKey: `sb-${PROJECT_ID}-auth-token`,
    storage: adaptiveStorage
  }
});

export const DEFAULT_AVATAR = "https://upload.wikimedia.org/wikipedia/commons/8/89/Portrait_Placeholder.png";

export const getLocalTodayKey = (): string => {
  const now = new Date();
  return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
};

export const isGuest = (userId: string | undefined): boolean => {
  if (!userId) return false;
  return userId.startsWith('guest_') || localStorage.getItem('healthy_hub_guest_session') === 'true';
};

export const getGuestUser = (): User => ({
  id: 'guest_elite_member',
  email: 'guest@healthyhub.com',
  app_metadata: {},
  user_metadata: { full_name: 'Guest Elite' },
  aud: 'authenticated',
  created_at: new Date().toISOString()
});

export const signInAsGuest = () => {
  localStorage.setItem('healthy_hub_guest_session', 'true');
  window.location.reload();
};

export const syncDailyActivity = async (userId: string, steps: number, calories: number, stepGoal: number, distanceKm: number = 0) => {
  if (isGuest(userId)) return;
  const todayKey = getLocalTodayKey();
  try {
    const { error } = await supabase.from('daily_activity').upsert({ 
      user_id: userId, 
      activity_date: todayKey, 
      steps, 
      calories_burned: calories, 
      distance_km: distanceKm,
      is_target_met: steps >= stepGoal,
      updated_at: new Date().toISOString()
    }, { onConflict: 'user_id, activity_date' });
    if (error) throw error;
  } catch (e) {
    console.error(`Activity Sync Error:`, e);
  }
};

export const fetchFullUserDashboard = async (userId: string) => {
  if (isGuest(userId)) {
    return {
      profile: {
        id: userId, name: 'Guest Elite', email: 'guest@healthyhub.com', avatarUrl: DEFAULT_AVATAR,
        goals: { stepGoal: 10000, calorieGoal: 2000, distanceGoal: 5.0 }, metrics: {}
      },
      todayActivity: null, foodLogs: [], chatHistory: []
    };
  }
  try {
    const todayKey = getLocalTodayKey();
    const { data: profileData } = await supabase.from('profiles').select('*').eq('id', userId).maybeSingle();
    if (!profileData) return null;
    const { data: activityData } = await supabase.from('daily_activity').select('*').eq('user_id', userId).eq('activity_date', todayKey).maybeSingle();
    const [foodRes, chatRes] = await Promise.all([
      supabase.from('food_logs').select('*').eq('user_id', userId).order('created_at', { ascending: false }).limit(5),
      supabase.from('chat_history').select('*').eq('user_id', userId).order('created_at', { ascending: true }).limit(10)
    ]);
    return {
      profile: mapProfileToAppFormat(profileData),
      todayActivity: activityData || null,
      foodLogs: foodRes.data as FoodLogDB[] || [],
      chatHistory: chatRes.data as ChatHistoryDB[] || []
    };
  } catch (e) {
    return null;
  }
};

const mapProfileToAppFormat = (dbProfile: any): UserProfile => {
  const safeGoals = dbProfile.goals || {};
  return {
    id: dbProfile.id,
    name: dbProfile.name || 'Elite Member',
    email: dbProfile.email || '',
    avatarUrl: dbProfile.avatar_url || DEFAULT_AVATAR,
    currentStreak: dbProfile.current_streak || 0,
    currentPlanName: dbProfile.current_plan_name,
    goals: {
        stepGoal: dbProfile.target_steps || dbProfile.daily_step_goal || safeGoals.stepGoal || 10000,
        calorieGoal: dbProfile.target_calories || dbProfile.daily_calorie_goal || safeGoals.calorieGoal || 2000,
        proteinGoal: dbProfile.target_protein || safeGoals.proteinGoal || 150,
        distanceGoal: Number(safeGoals.distanceGoal) || 5.0
    },
    metrics: dbProfile.metrics || {}
  };
};

export const onAuthStateChanged = (callback: (user: User | null) => void) => {
  const guestActive = localStorage.getItem('healthy_hub_guest_session') === 'true';
  if (guestActive) callback(getGuestUser());
  return supabase.auth.onAuthStateChange((_event, session) => {
    if (session?.user) {
      localStorage.removeItem('healthy_hub_guest_session');
      callback(session.user);
    } else if (!guestActive) {
      callback(null);
    }
  }).data.subscription.unsubscribe;
};

export const signInWithEmailAndPassword = async (email: string, psw: string) => {
  performMaintenance();
  const { data, error } = await supabase.auth.signInWithPassword({ email, password: psw });
  if (error) throw error;
  localStorage.removeItem('healthy_hub_guest_session');
  return data;
};

export const signOut = async () => {
  localStorage.removeItem('healthy_hub_guest_session');
  await supabase.auth.signOut({ scope: 'local' });
};

export const createUserWithEmailAndPassword = async (email: string, psw: string) => {
  performMaintenance();
  const { data, error } = await supabase.auth.signUp({ email, password: psw });
  if (error) throw error;
  localStorage.removeItem('healthy_hub_guest_session');
  return { data };
};

export const createUserDocument = async (user: User, name: string) => {
  if (isGuest(user.id)) return;
  await supabase.from('profiles').upsert({ id: user.id, email: user.email, name, avatar_url: DEFAULT_AVATAR });
};

export const updateProfile = async (user: User, profile: { displayName?: string, photoURL?: string }) => {
  if (isGuest(user.id)) return;
  await supabase.auth.updateUser({ data: { full_name: profile.displayName, avatar_url: profile.photoURL } });
  const updateData: any = {};
  if (profile.displayName) updateData.name = profile.displayName;
  if (profile.photoURL) updateData.avatar_url = profile.photoURL;
  if (Object.keys(updateData).length > 0) {
    await supabase.from('profiles').update(updateData).eq('id', user.id);
  }
};

export const sendPasswordResetEmail = async (email: string) => {
  const { error } = await supabase.auth.resetPasswordForEmail(email);
  if (error) throw error;
};

export const fetchChatHistory = async (userId: string) => {
  if (isGuest(userId)) return [];
  const { data, error } = await supabase.from('chat_history').select('*').eq('user_id', userId).order('created_at', { ascending: true });
  if (error) throw error;
  return data || [];
};

export const saveChatMessage = async (userId: string, message: string, isUserMessage: boolean, planData?: any) => {
  if (isGuest(userId)) return;
  const { error } = await supabase.from('chat_history').insert({
    user_id: userId,
    message,
    is_user_message: isUserMessage,
    plan_data: planData
  });
  if (error) throw error;
};

export const clearChatHistory = async (userId: string) => {
  if (isGuest(userId)) return;
  const { error } = await supabase.from('chat_history').delete().eq('user_id', userId);
  if (error) throw error;
};

export const updateUserMetrics = async (userId: string, metrics: UserMetrics) => {
  if (isGuest(userId)) return;
  const { error } = await supabase.from('profiles').update({ 
    metrics,
    height: metrics.height,
    weight: metrics.weight
  }).eq('id', userId);
  if (error) throw error;
};

export const updateUserTargets = async (userId: string, planData: any) => {
  if (isGuest(userId)) return;
  const { error } = await supabase.from('profiles').update({
    target_steps: planData.target_steps || planData.steps,
    target_calories: planData.target_calories || planData.calories,
    target_protein: planData.target_protein || planData.protein,
    current_plan_name: planData.plan_name
  }).eq('id', userId);
  if (error) throw error;
};

export const submitAiFeedback = async (imageUrl: string, prediction: string, feedback: string) => {
  const { data: { user } } = await supabase.auth.getUser();
  if (!user || isGuest(user.id)) return;
  await supabase.from('ai_feedback').insert({
    user_id: user.id,
    image_url: imageUrl,
    prediction,
    feedback
  });
};

export const completeOnboarding = async (user: User, profileData: any, activityGoals: ActivityData) => {
  if (isGuest(user.id)) return { ...profileData, id: user.id };

  const { error: profileError } = await supabase.from('profiles').upsert({
    id: user.id,
    email: profileData.email,
    name: profileData.name,
    avatar_url: profileData.avatarUrl || DEFAULT_AVATAR,
    metrics: profileData.metrics,
    target_steps: activityGoals.stepGoal,
    target_calories: activityGoals.calorieGoal,
    height: profileData.metrics.height,
    weight: profileData.metrics.weight
  });

  if (profileError) throw profileError;

  return mapProfileToAppFormat({
    ...profileData,
    id: user.id,
    avatar_url: profileData.avatarUrl,
    target_steps: activityGoals.stepGoal,
    target_calories: activityGoals.calorieGoal
  });
};

export const fetchSavedWorkouts = async (userId: string) => {
  if (isGuest(userId)) return [];
  const { data, error } = await supabase.from('saved_workouts').select('*').eq('user_id', userId).order('created_at', { ascending: false });
  if (error) throw error;
  return data || [];
};

export const saveWorkout = async (userId: string, plan: WorkoutPlan) => {
  if (isGuest(userId)) return;
  const { error } = await supabase.from('saved_workouts').insert({
    user_id: userId,
    plan_data: plan
  });
  if (error) throw error;
};

export const deleteWorkout = async (id: string) => {
  const { error } = await supabase.from('saved_workouts').delete().eq('id', id);
  if (error) throw error;
};

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  createUserDocument, 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  updateProfile,
  sendPasswordResetEmail,
  signInAsGuest,
  signOut,
  User
} from '../services/supabase'; 
import { Loader2, Eye, EyeOff, AlertCircle, User as UserIcon, Mail, Lock, CheckCircle, Camera, RefreshCw, ChevronRight, UserCircle2, Check, ArrowRight, Clock, DatabaseZap, UserPlus, ShieldAlert } from 'lucide-react';
import Logo from './Logo';

interface AuthProps {
  onLoginSuccess: () => void;
}

const Auth: React.FC<AuthProps> = ({ onLoginSuccess }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);
  const [quotaError, setQuotaError] = useState(false);
  const [isCredentialError, setIsCredentialError] = useState(false);

  const [lockoutTimer, setLockoutTimer] = useState(0);
  const [rememberMe, setRememberMe] = useState(false);

  const [showCamera, setShowCamera] = useState(false);
  const [tempUser, setTempUser] = useState<User | null>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const [isResetModalOpen, setIsResetModalOpen] = useState(false);
  const [resetEmail, setResetEmail] = useState('');
  const [resetError, setResetError] = useState<string | null>(null);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  useEffect(() => {
    const savedEmail = localStorage.getItem('healthy_hub_remembered_email');
    if (savedEmail) {
      setEmail(savedEmail);
      setRememberMe(true);
    }
  }, []);

  useEffect(() => {
    let interval: number;
    if (lockoutTimer > 0) {
      interval = window.setInterval(() => {
        setLockoutTimer((prev) => prev - 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [lockoutTimer]);

  const nuclearReset = async () => {
    await signOut();
    localStorage.clear();
    window.location.reload();
  };

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'user', width: { ideal: 500 }, height: { ideal: 500 } }
      });
      setStream(mediaStream);
      setTimeout(() => {
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
          videoRef.current.play().catch(e => console.error("Video play failed", e));
        }
      }, 100);
    } catch (err) {
      setError("Camera access denied.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(t => t.stop());
      setStream(null);
    }
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const size = Math.min(video.videoWidth, video.videoHeight);
      canvas.width = size;
      canvas.height = size;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        const startX = (video.videoWidth - size) / 2;
        const startY = (video.videoHeight - size) / 2;
        ctx.drawImage(video, startX, startY, size, size, 0, 0, size, size);
        const base64 = canvas.toDataURL('image/jpeg', 0.8);
        setCapturedImage(base64);
        stopCamera();
      }
    }
  };

  const handleRetake = () => {
    setCapturedImage(null);
    startCamera();
  };

  const handleSaveAvatar = async () => {
    if (!capturedImage || !tempUser) return;
    setIsLoading(true);
    try {
      await updateProfile(tempUser, { photoURL: capturedImage });
      onLoginSuccess();
    } catch (e) {
      setError("Failed to save avatar.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleSkipAvatar = () => {
    stopCamera();
    onLoginSuccess();
  };

  const handleGuestMode = () => {
    setIsLoading(true);
    signInAsGuest();
  };

  const handleResetPassword = async () => {
    if (!resetEmail) {
      setResetError("Email required.");
      return;
    }
    setIsLoading(true);
    setResetError(null);
    try {
      await sendPasswordResetEmail(resetEmail);
      setSuccessMsg("Reset instructions dispatched.");
      setTimeout(() => {
        setIsResetModalOpen(false);
        setSuccessMsg(null);
        setResetEmail('');
      }, 2500);
    } catch (err: any) {
      setResetError(err.message || "Reset failed.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    if (lockoutTimer > 0) return;

    setError(null);
    setQuotaError(false);
    setIsCredentialError(false);
    setIsLoading(true);

    const performAuth = async () => {
      if (isLogin) {
        await signInWithEmailAndPassword(email, password);
        if (rememberMe) {
          localStorage.setItem('healthy_hub_remembered_email', email);
        } else {
          localStorage.removeItem('healthy_hub_remembered_email');
        }
        onLoginSuccess();
      } else {
        if (password !== confirmPassword) throw new Error("Passwords do not match.");
        if (password.length < 6) throw new Error("Password must be at least 6 characters.");
        const { data } = await createUserWithEmailAndPassword(email, password);
        if (rememberMe) {
          localStorage.setItem('healthy_hub_remembered_email', email);
        } else {
          localStorage.removeItem('healthy_hub_remembered_email');
        }
        const user = data.user;
        if (user) {
            if (name) {
                await updateProfile(user, { displayName: name });
                await createUserDocument(user, name);
            } else {
                await createUserDocument(user, 'Elite User');
            }
            setTempUser(user);
            setShowCamera(true);
            startCamera();
        }
      }
    };

    try {
      await performAuth();
    } catch (err: any) {
      console.error('❌ AUTH ERROR:', err);
      if (navigator.vibrate) navigator.vibrate([100, 50, 100]);

      if (err.message?.toLowerCase().includes('quota') || err.name === 'QuotaExceededError') {
        setQuotaError(true);
        localStorage.clear();
        try {
          await performAuth();
          setQuotaError(false);
          return;
        } catch (retryErr: any) {
          setError("Storage full. Clear browser data.");
          setIsLoading(false);
          return;
        }
      }

      let msg = err.message || "Auth Protocol Refused.";
      const lowerMsg = msg.toLowerCase();

      if (lowerMsg.includes("invalid login credentials")) {
        msg = "Credentials not recognized. Proceed to 'Sign Up' if this is your first calibration.";
        setIsCredentialError(true);
      } else if (lowerMsg.includes("rate limit") || lowerMsg.includes("too many requests")) {
        msg = "Neural network throttled. Wait 60s.";
        setLockoutTimer(60);
      }

      setError(msg);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="h-screen w-full flex flex-col bg-black font-sans relative overflow-y-auto no-scrollbar scroll-smooth">
      {/* 1. Background & Atmosphere: Deep Radial Gradient */}
      <div className="fixed inset-0 z-0 bg-[radial-gradient(circle_at_center,_#1a1a1a_0%,_#000000_100%)] pointer-events-none" />

      {/* Subtle Mesh/Grid Pattern */}
      <div className="fixed inset-0 z-0 bg-[linear-gradient(rgba(255,255,255,0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.02)_1px,transparent_1px)] bg-[size:40px_40px] [mask-image:radial-gradient(ellipse_at_center,black_40%,transparent_100%)] pointer-events-none"></div>

      <AnimatePresence>
        {showCamera && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 bg-black/95 backdrop-blur-xl flex flex-col items-center justify-center p-6"
          >
             <div className="w-full max-w-md flex flex-col items-center space-y-8">
                <div className="text-center">
                   <h2 className="text-2xl font-black text-white uppercase tracking-widest font-cyber mb-2">Bio-Identity</h2>
                   <p className="text-gray-400 text-xs tracking-wider">Capture profile avatar for the elite network.</p>
                </div>
                <div className="relative w-64 h-64 rounded-full overflow-hidden border-4 border-luxury-neon shadow-[0_0_40px_rgba(206,242,69,0.3)] bg-gray-900">
                    {capturedImage ? (
                        <img src={capturedImage} className="w-full h-full object-cover" alt="Captured" />
                    ) : (
                        <>
                           <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover mirror-mode" />
                           <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                              {!stream && <Loader2 className="animate-spin text-luxury-neon" />}
                           </div>
                        </>
                    )}
                </div>
                <canvas ref={canvasRef} className="hidden" />
                <div className="flex gap-4 w-full max-w-xs">
                   {capturedImage ? (
                      <>
                        <button onClick={handleRetake} className="flex-1 py-4 bg-white/10 rounded-2xl text-white font-bold flex items-center justify-center gap-2 border border-white/10 hover:bg-white/20 transition-all">
                           <RefreshCw size={18} /> Retake
                        </button>
                        <button onClick={handleSaveAvatar} disabled={isLoading} className="flex-1 py-4 bg-luxury-neon rounded-2xl text-black font-black uppercase tracking-widest flex items-center justify-center gap-2 shadow-[0_0_20px_rgba(206,242,69,0.4)]">
                           {isLoading ? <Loader2 className="animate-spin" /> : <><CheckCircle size={18} /> Save</>}
                        </button>
                      </>
                   ) : (
                      <button onClick={capturePhoto} className="w-full py-4 bg-white text-black font-black uppercase tracking-widest rounded-2xl flex items-center justify-center gap-2 shadow-xl hover:scale-105 transition-transform">
                          <Camera size={20} /> Capture
                      </button>
                   )}
                </div>
                <button onClick={handleSkipAvatar} className="text-gray-500 text-xs font-bold uppercase tracking-widest hover:text-white transition-colors">
                   Skip Initialization <ChevronRight size={10} className="inline" />
                </button>
             </div>
          </motion.div>
        )}
      </AnimatePresence>

      {!showCamera && (
        <div className="relative z-10 min-h-screen w-full flex flex-col items-center justify-center p-6 py-12 lg:py-24">

          {/* 2. The Login Card (Glassmorphism) */}
          <motion.div 
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            className="w-full max-w-md bg-white/5 backdrop-blur-xl rounded-[24px] p-8 md:p-12 border border-white/10 shadow-2xl my-auto relative overflow-hidden"
          >
            {/* Ambient Glow inside card */}
            <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-32 bg-luxury-neon/5 blur-[60px] pointer-events-none"></div>

            <div className="flex flex-col items-center mb-10 text-center relative z-10">
              <Logo className="h-[100px] w-auto mb-6 drop-shadow-[0_0_25px_rgba(206,242,69,0.2)]" />
              {/* 5. Typography: Modern, wide font */}
              <p className="text-[10px] text-gray-400 font-black uppercase tracking-[0.5em] leading-relaxed font-cyber">Elite Fitness Ecosystem</p>
            </div>

            <AnimatePresence>
              {error && (
                <motion.div 
                  initial={{ height: 0, opacity: 0, scale: 0.95 }} 
                  animate={{ height: 'auto', opacity: 1, scale: 1 }} 
                  exit={{ height: 0, opacity: 0, scale: 0.95 }}
