};

export const syncDailyActivity = async (userId: string, steps: number, calories: number, stepGoal: number, distanceKm: number = 0) => {
  if (isGuest(userId)) return;
  const todayKey = getLocalTodayKey();
  try {
    const { error } = await supabase.from('daily_activity').upsert({ 
      user_id: userId, 
      activity_date: todayKey, 
      steps, 
      calories_burned: calories, 
      distance_km: distanceKm,
      is_target_met: steps >= stepGoal,
      updated_at: new Date().toISOString()
    }, { onConflict: 'user_id, activity_date' });
    if (error) throw error;
  } catch (e) {
    console.error(`Activity Sync Error:`, e);
  }
};

export const fetchFullUserDashboard = async (userId: string) => {
  if (isGuest(userId)) {
    return {
      profile: {
        id: userId, name: 'Guest Elite', email: 'guest@healthyhub.com', avatarUrl: DEFAULT_AVATAR,
        goals: { stepGoal: 10000, calorieGoal: 2000, distanceGoal: 5.0 }, metrics: {}
      },
      todayActivity: null, foodLogs: [], chatHistory: []
    };
  }
  try {
    const todayKey = getLocalTodayKey();
    const { data: profileData } = await supabase.from('profiles').select('*').eq('id', userId).maybeSingle();
    if (!profileData) return null;
    const { data: activityData } = await supabase.from('daily_activity').select('*').eq('user_id', userId).eq('activity_date', todayKey).maybeSingle();
    const [foodRes, chatRes] = await Promise.all([
      supabase.from('food_logs').select('*').eq('user_id', userId).order('created_at', { ascending: false }).limit(5),
      supabase.from('chat_history').select('*').eq('user_id', userId).order('created_at', { ascending: true }).limit(10)
    ]);
    return {
      profile: mapProfileToAppFormat(profileData),
      todayActivity: activityData || null,
      foodLogs: foodRes.data as FoodLogDB[] || [],
      chatHistory: chatRes.data as ChatHistoryDB[] || []
    };
  } catch (e) {
    return null;
  }
};

const mapProfileToAppFormat = (dbProfile: any): UserProfile => {
  const safeGoals = dbProfile.goals || {};
  return {
    id: dbProfile.id,
    name: dbProfile.name || 'Elite Member',
    email: dbProfile.email || '',
    avatarUrl: dbProfile.avatar_url || DEFAULT_AVATAR,
    currentStreak: dbProfile.current_streak || 0,
    currentPlanName: dbProfile.current_plan_name,
    goals: {
        stepGoal: dbProfile.target_steps || dbProfile.daily_step_goal || safeGoals.stepGoal || 10000,
        calorieGoal: dbProfile.target_calories || dbProfile.daily_calorie_goal || safeGoals.calorieGoal || 2000,
        proteinGoal: dbProfile.target_protein || safeGoals.proteinGoal || 150,
        distanceGoal: Number(safeGoals.distanceGoal) || 5.0
    },
    metrics: dbProfile.metrics || {}
  };
};

export const onAuthStateChanged = (callback: (user: User | null) => void) => {
  const guestActive = localStorage.getItem('healthy_hub_guest_session') === 'true';
  if (guestActive) callback(getGuestUser());
  return supabase.auth.onAuthStateChange((_event, session) => {
    if (session?.user) {
      localStorage.removeItem('healthy_hub_guest_session');
      callback(session.user);
    } else if (!guestActive) {
      callback(null);
    }
  }).data.subscription.unsubscribe;
};

