import React, { useState, useEffect, useRef } from 'react';
import { MapContainer, TileLayer, Polyline, Marker, useMap } from 'react-leaflet';
import L from 'leaflet';
import { motion } from 'framer-motion';
import { Play, Square, Navigation as NavIcon, Timer, Footprints, Map as MapIcon, Loader2 } from 'lucide-react';
// Corrected import to use the existing upsertDailyActivity function.
import { supabase, upsertDailyActivity } from '../services/supabase';

interface MapTrackingScreenProps {
  userHeight?: number;
}

const CHENNAI_COORDS: [number, number] = [13.0827, 80.2707];

const locationIcon = L.divIcon({
  className: 'custom-location-icon',
  html: `<div class="w-5 h-5 bg-blue-500 rounded-full border-4 border-white shadow-[0_0_20px_rgba(59,130,246,0.8)] animate-pulse"></div>`,
  iconSize: [20, 20],
  iconAnchor: [10, 10]
});

const MapController = ({ center }: { center: [number, number] | null }) => {
  const map = useMap();
  useEffect(() => {
    if (center) {
      map.flyTo(center, 18, { animate: true });
    }
  }, [center, map]);
  return null;
};

const MapTrackingScreen: React.FC<MapTrackingScreenProps> = ({ userHeight = 175 }) => {
  const [isStarted, setIsStarted] = useState(false);
  const [position, setPosition] = useState<[number, number] | null>(null);
  const [path, setPath] = useState<[number, number][]>([]);
  const [distance, setDistance] = useState(0); 
  const [elapsedTime, setElapsedTime] = useState(0);
  const [userId, setUserId] = useState<string | null>(null);

  const watchId = useRef<number | null>(null);
  const timerId = useRef<number | null>(null);

  useEffect(() => {
    supabase.auth.getUser().then(({ data }) => {
      if (data.user) setUserId(data.user.id);
    });

    if ("geolocation" in navigator) {
      watchId.current = navigator.geolocation.watchPosition(
        (pos) => {
          const newPos: [number, number] = [pos.coords.latitude, pos.coords.longitude];
          setPosition(newPos);

          if (isStarted) {
            setPath(prev => {
              if (prev.length > 0) {
                const last = prev[prev.length - 1];
                const d = L.latLng(last[0], last[1]).distanceTo(L.latLng(newPos[0], newPos[1]));
                if (d > 2) { 
                  setDistance(prevD => prevD + d);
                  return [...prev, newPos];
                }
              }
              return prev.length === 0 ? [newPos] : prev;
            });
          }
        },
        null,
        { enableHighAccuracy: true }
      );
    }
    return () => { if (watchId.current) navigator.geolocation.clearWatch(watchId.current); };
  }, [isStarted]);

  useEffect(() => {
    if (isStarted) {
      timerId.current = window.setInterval(() => setElapsedTime(t => t + 1), 1000);
    } else if (timerId.current) {
      clearInterval(timerId.current);
    }
    return () => { if (timerId.current) clearInterval(timerId.current); };
  }, [isStarted]);

  const toggleTracking = () => {
    if (!isStarted) {
      setDistance(0);
      setElapsedTime(0);
      setPath(position ? [position] : []);
    } else {
      _finalizeSync();
    }
    setIsStarted(!isStarted);
  };

  const _finalizeSync = async () => {
    if (!userId) return;
    const strideLengthCm = userHeight * 0.415;
    const steps = Math.floor((distance * 100) / strideLengthCm);
    const calories = Math.floor(steps * 0.04);
    // Updated call to upsertDailyActivity with correct parameter count.
    upsertDailyActivity(userId, steps, calories, parseFloat((distance/1000).toFixed(3)));
  };

  const formatTime = (s: number) => {
    const m = Math.floor(s / 60);
    const sec = s % 60;
    return `${m.toString().padStart(2, '0')}:${sec.toString().padStart(2, '0')}`;
  };

  return (
    <div className="relative h-full w-full bg-black overflow-hidden">
      <div className="absolute inset-0 z-0">
        <MapContainer center={CHENNAI_COORDS} zoom={13} className="h-full w-full" zoomControl={false}>
          <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" className="map-tiles-dark" />
          <MapController center={position} />
          {path.length > 1 && <Polyline positions={path} pathOptions={{ color: '#CEF245', weight: 5 }} />}
          {position && <Marker position={position} icon={locationIcon} />}
        </MapContainer>
        {!position && (
           <div className="absolute inset-0 bg-black/40 backdrop-blur-sm flex flex-col items-center justify-center z-10">
              <Loader2 className="animate-spin text-luxury-neon mb-4" />
              <p className="text-[10px] font-black uppercase tracking-[0.3em] text-white">Acquiring Location...</p>
           </div>
        )}
      </div>

      <motion.div 
        initial={{ y: 50, opacity: 0 }} animate={{ y: 0, opacity: 1 }}
        className="absolute bottom-6 left-6 right-6 z-20 glass-panel rounded-[2rem] p-6 shadow-2xl border border-white/10"
      >
        <div className="flex flex-col gap-6">
          <div className="flex justify-between items-center px-2">
            <div className="flex flex-col items-center gap-1">
              <Timer size={14} className="text-gray-500 mb-1" />
              <span className="text-xl font-black text-white tabular-nums">{formatTime(elapsedTime)}</span>
              <span className="text-[8px] font-black text-gray-600 uppercase tracking-widest">Time</span>
            </div>
            <div className="w-px h-8 bg-white/10"></div>
            <div className="flex flex-col items-center gap-1">
              <MapIcon size={14} className="text-gray-500 mb-1" />
              <span className="text-xl font-black text-white tabular-nums">{(distance/1000).toFixed(2)}</span>
              <span className="text-[8px] font-black text-gray-600 uppercase tracking-widest">KM</span>
            </div>
            <div className="w-px h-8 bg-white/10"></div>
            <div className="flex flex-col items-center gap-1">
              <Footprints size={14} className="text-gray-500 mb-1" />
              <span className="text-xl font-black text-white tabular-nums">{Math.floor((distance*100)/(userHeight*0.415))}</span>
              <span className="text-[8px] font-black text-gray-600 uppercase tracking-widest">Steps</span>
            </div>
          </div>

          <button 
            onClick={toggleTracking}
            disabled={!position}
            className={`w-full py-4 rounded-2xl flex items-center justify-center gap-3 font-black uppercase text-[10px] tracking-[0.2em] transition-all disabled:opacity-30 ${isStarted ? 'bg-red-500 text-white' : 'bg-luxury-neon text-black shadow-[0_0_20px_rgba(206,242,69,0.3)]'}`}
          >
            {isStarted ? <><Square size={14} fill="currentColor" /> Stop Track</> : <><Play size={14} fill="currentColor" /> Start Track</>}
          </button>
        </div>
      </motion.div>
    </div>
  );
};

export default MapTrackingScreen;

import { useState, useEffect, useRef, useCallback } from 'react';
import { supabase, upsertDailyActivity, processStreakUpdate, getLocalTodayKey } from '../services/supabase';

interface StepTrackerHook {
  steps: number;
  calories: number;
  distance: number;
  streak: number;
  history: any[];
  isTracking: boolean;
  toggleTracking: () => Promise<void>;
  error: string | null;
  isLoading: boolean;
}

const useStepTracker = (userId: string | null, stepGoal: number): StepTrackerHook => {
  const [steps, setSteps] = useState(0);
  const [calories, setCalories] = useState(0);
  const [distance, setDistance] = useState(0);
  const [streak, setStreak] = useState(0);
  const [history, setHistory] = useState<any[]>([]);
  const [isTracking, setIsTracking] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Replaced NodeJS.Timeout with any for compatibility in a web/browser context.
  const syncTimer = useRef<any>(null);
  const lastSyncValue = useRef(0);
  const lastStepTime = useRef(0);
  const lastMag = useRef(0);
  const wakeLock = useRef<any>(null);

  // --- INITIALIZATION ---
  useEffect(() => {
    const loadSessionData = async () => {
      if (!userId) {
          setIsLoading(false);
          return;
      }

      try {
        const today = getLocalTodayKey();

        // 1. Fetch Today's Current Progress
        const { data: activity } = await supabase
          .from('daily_activity')
          .select('*')
          .eq('user_id', userId)
          .eq('activity_date', today)
          .maybeSingle();

        if (activity) {
          setSteps(activity.steps || 0);
          setCalories(activity.calories_burned || 0);
          setDistance(activity.distance_km || 0);
          lastSyncValue.current = activity.steps || 0;
        }

        // 2. Fetch Profile Streak
        const { data: profile } = await supabase
          .from('profiles')
          .select('current_streak, last_active_date')
          .eq('id', userId)
          .maybeSingle();

        if (profile) {
          setStreak(profile.current_streak || 0);
        }

        // 3. Fetch History (7 Days)
        const { data: hist } = await supabase
          .from('daily_activity')
          .select('*')
          .eq('user_id', userId)
          .order('activity_date', { ascending: false })
          .limit(7);

        setHistory(hist || []);

      } catch (e) {
        console.error("Initialization Error:", e);
      } finally {
        setIsLoading(false);
      }
    };

    loadSessionData();
  }, [userId]);

  // --- PERSISTENCE ENGINE (Debounced) ---
  useEffect(() => {
    if (!userId || steps === lastSyncValue.current) return;

    if (syncTimer.current) clearTimeout(syncTimer.current);

    syncTimer.current = setTimeout(async () => {
      await upsertDailyActivity(userId, steps, Math.floor(calories), parseFloat(distance.toFixed(3)));

      // Check for streak update if goal met
      if (steps >= stepGoal) {
          const newStreak = await processStreakUpdate(userId, steps, stepGoal);
          if (newStreak) setStreak(newStreak);
      }

      lastSyncValue.current = steps;
    }, 1500); // 1.5s debounce

    return () => { if (syncTimer.current) clearTimeout(syncTimer.current); };
  }, [steps, userId, calories, distance, stepGoal]);

  // --- SENSOR LOGIC ---
  const handleMotion = useCallback((event: DeviceMotionEvent) => {
    const acc = event.accelerationIncludingGravity;
    if (!acc) return;
    const { x, y, z } = acc;
    if (x === null || y === null || z === null) return;

    const rawMag = Math.sqrt(x*x + y*y + z*z);
    const mag = 0.8 * rawMag + 0.2 * lastMag.current;
    lastMag.current = mag;

    const now = Date.now();
    if (mag > 13.0) {
      if (now - lastStepTime.current > 600) {
         setSteps(prev => {
             const next = prev + 1;
             setCalories(next * 0.04);
             setDistance(next * 0.0008);
             return next;
         });
         lastStepTime.current = now;
         if (navigator.vibrate) navigator.vibrate(15);
      }
    }
  }, []);

  const toggleTracking = async () => {
    if (isTracking) {
      window.removeEventListener('devicemotion', handleMotion);
      if (wakeLock.current) await wakeLock.current.release();
      setIsTracking(false);
    } else {
      // Permission request for iOS
      // @ts-ignore
      if (typeof DeviceMotionEvent !== 'undefined' && typeof DeviceMotionEvent.requestPermission === 'function') {
        try {
            // @ts-ignore
            const permission = await DeviceMotionEvent.requestPermission();
            if (permission !== 'granted') {
                setError("Sensor access denied.");
                return;
            }
        } catch (e) {
            setError("Sensors unavailable.");
            return;
        }
      }

      window.addEventListener('devicemotion', handleMotion);
      if ('wakeLock' in navigator) {
          try { wakeLock.current = await (navigator as any).wakeLock.request('screen'); } catch (e) {}
      }
      setIsTracking(true);
    }
  };

  return { steps, calories, distance, streak, history, isTracking, toggleTracking, error, isLoading };
};

