            <div className="absolute bottom-0 left-0 right-0 z-30 pb-[calc(2rem+env(safe-area-inset-bottom))] pt-8 bg-gradient-to-t from-black/90 to-transparent flex items-center justify-evenly">

               {/* Left: Gallery Icon */}
               <button 
