import React, { useState, useEffect } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import { 
  onAuthStateChanged,
  User,
  fetchFullUserDashboard,
  supabase,
  mapProfileToAppFormat,
  DEFAULT_AVATAR
} from './services/supabase';

import Navigation from './components/Navigation';
import Dashboard from './components/Dashboard';
import FoodLens from './components/FoodLens';
import BMIHub from './components/BMIHub';
import MapTrackingScreen from './components/MapTrackingScreen';
import ChatBot from './components/ChatBot';
import ProfileScreen from './components/ProfileScreen';
import OnboardingScreen from './components/OnboardingScreen'; 
import WorkoutLab from './components/WorkoutLab';
import Auth from './components/Auth';
import { ViewState, ActivityData, FoodHistoryItem, UserMetrics } from './types';
import useLocalStorage from './hooks/useLocalStorage';
import useStepTracker from './hooks/useStepTracker';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [userProfile, setUserProfile] = useState<any>(null);
  const [isAuthChecking, setIsAuthChecking] = useState(true); 
  const [isProfileChecking, setIsProfileChecking] = useState(false);
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);

  // Biometric Synchronization Hook
  const { steps, calories, distance, streak, history, isTracking, toggleTracking, isLoading: biometricLoading } = useStepTracker(
    currentUser?.id || null, 
    userProfile?.goals?.stepGoal || 10000
  );

  const [bmiMetrics, setBmiMetrics] = useLocalStorage<UserMetrics>('bmi_metrics', { height: 175, weight: 70 });
  const [foodHistory, setFoodHistory] = useLocalStorage<FoodHistoryItem[]>('food_history', []);
  const [adaptiveGoalsEnabled, setAdaptiveGoalsEnabled] = useLocalStorage<boolean>('adaptive_goals_enabled', true);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(async (user) => {
      if (user) {
        // --- GUEST LOGIC ---
        if (user.id.startsWith('guest_')) {
             setCurrentUser(user);
             setUserProfile({
                 id: user.id,
                 name: 'Guest Elite',
                 email: 'guest@elite.com',
                 avatarUrl: DEFAULT_AVATAR,
                 metrics: { height: 175, weight: 75, age: 25 },
                 goals: { stepGoal: 10000, calorieGoal: 2000, distanceGoal: 5 }
             });
             setIsAuthChecking(false);
             return;
        }

        // --- AUTHENTICATED USER LOGIC ---
        setCurrentUser(user);
        setIsProfileChecking(true);

        try {
          // 1. Explicitly check if a VALID profile exists in the DB
          const { data: profile } = await supabase
            .from('profiles')
            .select('*')
            .eq('id', user.id)
            .maybeSingle();

          // 2. Validate critical fields (Name & DOB are essential to bypass onboarding)
          const isProfileValid = profile && profile.name && profile.metrics && profile.metrics.dob;

          if (isProfileValid) {
             // 3. Profile Exists -> Fetch Dashboard Data & Go to Home
             const dashboardData = await fetchFullUserDashboard(user.id);

             if (dashboardData) {
                 setUserProfile(dashboardData.profile);
             } else {
                 // Fallback: If dashboard stats fail, at least load the profile to prevent Onboarding Loop
                 console.warn("Dashboard sync failed, loading fallback profile.");
                 setUserProfile(mapProfileToAppFormat(profile));
             }
             setCurrentView(ViewState.DASHBOARD);
          } else {
             // 4. Profile Missing/Incomplete -> Send to Setup
             console.log("Profile incomplete, redirecting to setup.");
             setUserProfile(null);
          }
        } catch (e) {
          console.error("Auth Gate Error:", e);
          // On critical error, fallback to null (Setup) is safer than broken Dashboard
          setUserProfile(null);
        } finally {
          setIsProfileChecking(false);
        }

      } else { 
        setCurrentUser(null); 
        setUserProfile(null);
      }
      setIsAuthChecking(false);
    });
    return () => { if (unsubscribe) unsubscribe(); };
  }, []);

  const handleAddToFoodHistory = (item: FoodHistoryItem) => {
    setFoodHistory(prev => [item, ...prev].slice(0, 5));
  };

  if (isAuthChecking || biometricLoading) return <div className="h-screen bg-black flex items-center justify-center text-luxury-neon animate-pulse text-[10px] uppercase tracking-[0.3em]">Initialising Ecosystem...</div>;
  if (!currentUser) return <Auth onLoginSuccess={() => {}} />;
  if (isProfileChecking) return <div className="h-screen bg-black flex items-center justify-center text-gray-400 text-[10px] uppercase tracking-[0.3em]">Synchronizing Records...</div>;

  if (!userProfile) {
     return <OnboardingScreen user={currentUser} onComplete={(p) => { setUserProfile(p); setCurrentView(ViewState.DASHBOARD); }} />;
  }

  const activityData: ActivityData = {
    steps,
    calories,
    distance,
    stepGoal: userProfile.goals?.stepGoal || 10000,
    calorieGoal: userProfile.goals?.calorieGoal || 2000,
    distanceGoal: 5.0,
    history: []
  };

  const pageTransition = {
    initial: { opacity: 0, x: 20 },
    animate: { opacity: 1, x: 0 },
    exit: { opacity: 0, x: -20 },
    transition: { type: 'spring', damping: 25, stiffness: 200 }
  };

  return (
    <div className="flex flex-col h-[100dvh] bg-black text-white relative overflow-hidden font-sans">
      <main className="flex-1 relative w-full overflow-hidden">
        <AnimatePresence mode="wait">
          {currentView === ViewState.DASHBOARD && (
            <motion.div key="dash" {...pageTransition} className="h-full w-full">
              <Dashboard 
                data={activityData} 
                onUpdateGoals={() => {}} 
                isTracking={isTracking} 
                onToggleTracking={toggleTracking} 
                foodHistory={foodHistory}
                adaptiveGoalsEnabled={adaptiveGoalsEnabled}
                onToggleAdaptiveGoals={setAdaptiveGoalsEnabled}
                streakValue={streak}
                activityHistory={history}
              />
            </motion.div>
          )}
          {currentView === ViewState.CHAT && (
            <motion.div key="chat" {...pageTransition} className="h-full w-full">
              <ChatBot metrics={bmiMetrics} activity={activityData} />
            </motion.div>
          )}
          {currentView === ViewState.FOOD_LENS && (
            <motion.div key="lens" {...pageTransition} className="h-full w-full">
              <FoodLens history={foodHistory} onAddToHistory={handleAddToFoodHistory} />
            </motion.div>
          )}
          {currentView === ViewState.BMI_HUB && (
            <motion.div key="bmi" {...pageTransition} className="h-full w-full">
              <BMIHub />
            </motion.div>
          )}
          {currentView === ViewState.MAP_TRACKER && (
            <motion.div key="map" {...pageTransition} className="h-full w-full">
              <MapTrackingScreen userHeight={bmiMetrics.height} />
            </motion.div>
          )}
          {currentView === ViewState.PROFILE && (
            <motion.div key="profile" {...pageTransition} className="h-full w-full">
              <ProfileScreen onUpdateMetrics={setBmiMetrics} />
            </motion.div>
          )}
          {currentView === ViewState.WORKOUT_LAB && (
            <motion.div key="lab" {...pageTransition} className="h-full w-full">
              <WorkoutLab metrics={bmiMetrics} />
            </motion.div>
          )}
        </AnimatePresence>
      </main>
      <Navigation currentView={currentView} setView={setCurrentView} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronRight, ArrowLeft, User, Ruler, Weight, Activity, Target, CheckCircle, Loader2, AlertCircle, LogOut } from 'lucide-react';
import { type User as SupabaseUser } from '@supabase/supabase-js';
import { Gender, ActivityLevel, FitnessGoal, UserProfile, ActivityData } from '../types';
import { completeOnboarding, DEFAULT_AVATAR, signOut, supabase } from '../services/supabase';

interface OnboardingScreenProps {
  user: SupabaseUser;
  onComplete: (profile: UserProfile) => void;
}

const OnboardingScreen: React.FC<OnboardingScreenProps> = ({ user, onComplete }) => {
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [isLoggingOut, setIsLoggingOut] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);

  // Form State
  const [name, setName] = useState(user.user_metadata?.full_name || '');
  const [gender, setGender] = useState<Gender>('Male');
  const [dob, setDob] = useState('');

  const [heightStr, setHeightStr] = useState('175');
  const [weightStr, setWeightStr] = useState('75');

  const [activityLevel, setActivityLevel] = useState<ActivityLevel>('Moderately Active');
  const [goal, setGoal] = useState<FitnessGoal>('Maintain');

  const [errors, setErrors] = useState({ height: '', weight: '' });

  const calculateAge = (dateString: string) => {
    const today = new Date();
    const birthDate = new Date(dateString);
    let age = today.getFullYear() - birthDate.getFullYear();
    const m = today.getMonth() - birthDate.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
        age--;
    }
    return age;
  };

  const validateStep2 = () => {
    const h = parseFloat(heightStr);
    const w = parseFloat(weightStr);
    let valid = true;
    const newErrors = { height: '', weight: '' };

    if (isNaN(h) || h < 50 || h > 250) {
        newErrors.height = 'Valid range: 50 - 250 cm';
        valid = false;
    }
    if (isNaN(w) || w < 20 || w > 300) {
        newErrors.weight = 'Valid range: 20 - 300 kg';
        valid = false;
    }

    setErrors(newErrors);
    return valid;
  };

  const handleNextStep2 = () => {
      if (validateStep2()) {
          nextStep();
      }
  };

  const handleBackToLogin = async () => {
    setIsLoggingOut(true);
    try {
      await signOut();
      window.location.href = window.location.origin;
    } catch (e) {
      console.error("Logout failed", e);
      setIsLoggingOut(false);
    }
  };

  const handleSaveAndStart = async () => {
    setSubmitError(null);
    setLoading(true);

    try {
        // 1. Validation
        if (!name.trim()) throw new Error("Please enter your display name.");
        if (!dob) throw new Error("Date of birth is required for bio-calculation.");

        const rawHeight = parseFloat(heightStr);
        const rawWeight = parseFloat(weightStr);
        const calculatedAge = dob ? calculateAge(dob) : 25;

        if (isNaN(rawHeight) || rawHeight <= 0) throw new Error("Invalid height input.");
        if (isNaN(rawWeight) || rawWeight <= 0) throw new Error("Invalid weight input.");

        // 2. CRITICAL: Get Fresh User ID for RLS Compliance
        // We ensure we have the absolute latest session to prevent RLS mismatches.
        const { data: { user: currentUser }, error: authError } = await supabase.auth.getUser();

        if (authError || !currentUser) {
            throw new Error("Secure session lost. Please log in again.");
        }

        const userId = currentUser.id; // This ID must match the 'id' in the upsert payload

        // 3. Calculation
        let bmr = (10 * rawWeight) + (6.25 * rawHeight) - (5 * calculatedAge);
        bmr += (gender === 'Male' ? 5 : -161);

        const multipliers: Record<ActivityLevel, number> = {
            'Sedentary': 1.2,
            'Lightly Active': 1.375,
            'Moderately Active': 1.55,
            'Very Active': 1.725
        };
        const tdee = bmr * multipliers[activityLevel];

        let calorieTarget = tdee;
        if (goal === 'Weight Loss') calorieTarget -= 500;
        if (goal === 'Muscle Gain') calorieTarget += 300;

        const metrics = {
            height: rawHeight,
            weight: rawWeight,
            age: calculatedAge,
            gender,
            dob,
            activityLevel,
            fitnessGoal: goal,
            lastWeightUpdate: Date.now(),
            lastHeightUpdate: Date.now()
        };

        const avatarUrlFromMetadata = currentUser.user_metadata?.avatar_url;

        const profileData: any = {
            name: name.trim(),
            email: currentUser.email || '',
            metrics
        };

        if (avatarUrlFromMetadata) {
            profileData.avatarUrl = avatarUrlFromMetadata;
        }

        let stepGoal = 8000;
        if (goal === 'Weight Loss') stepGoal += 2000;
        if (activityLevel === 'Very Active') stepGoal += 3000;
        if (activityLevel === 'Sedentary') stepGoal = 6000;

        const activityGoals: ActivityData = {
            steps: 0, calories: 0, distance: 0, history: [],
            stepGoal: stepGoal,
            calorieGoal: Math.round(calorieTarget),
            distanceGoal: parseFloat((stepGoal * 0.000762).toFixed(1))
        };

        // 4. Save to Database (Passing fresh currentUser)
        const savedProfile = await completeOnboarding(currentUser, profileData, activityGoals);
        onComplete(savedProfile);

    } catch (e: any) {
        console.error("Protocol Save Error:", e);
        setSubmitError(`Save Failed: ${e.message || "Unknown Error"}`);
        setLoading(false);
    }
  };

  const nextStep = () => setStep(s => s + 1);
  const prevStep = () => setStep(s => s - 1);

  return (
    <div className="h-screen w-full bg-black relative overflow-y-auto no-scrollbar scroll-smooth overscroll-contain">
       {/* Background Ambience */}
       <div className="fixed top-[-20%] right-[-20%] w-[80vw] h-[80vw] bg-luxury-neon/5 rounded-full blur-[100px] animate-pulse-slow pointer-events-none"></div>
       <div className="fixed bottom-[-20%] left-[-20%] w-[80vw] h-[80vw] bg-luxury-gold/5 rounded-full blur-[100px] animate-pulse-slow pointer-events-none"></div>

       <div className="relative z-10 w-full flex flex-col items-center min-h-full p-6 py-12 lg:py-20">

          <div className="w-full max-w-md mb-8 flex items-center justify-start shrink-0">
            <button 
              onClick={handleBackToLogin}
              disabled={isLoggingOut || loading}
              className="flex items-center gap-2 group px-4 py-2 rounded-full hover:bg-white/5 transition-all disabled:opacity-50"
            >
              <div className="p-2 bg-luxury-neon/10 rounded-full group-hover:bg-luxury-neon/20 transition-all">
                {isLoggingOut ? (
                  <Loader2 size={18} className="text-luxury-neon animate-spin" />
                ) : (
                  <ArrowLeft size={18} className="text-luxury-neon" />
                )}
              </div>
              <span className="text-[11px] font-black text-gray-500 group-hover:text-gray-300 uppercase tracking-[0.2em] transition-all">
                {isLoggingOut ? 'Disconnecting...' : 'Back to Login'}
              </span>
            </button>
          </div>

          <div className="w-full max-w-md glass-panel rounded-[3rem] p-1 border border-white/10 shadow-2xl relative overflow-hidden my-auto shrink-0">
             <AnimatePresence mode="wait">

                {/* STEP 1: IDENTITY */}
                {step === 1 && (
                    <motion.div key="step1" initial={{ opacity: 0, x: 50 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -50 }} className="p-8 space-y-6">
                        <div className="flex items-center gap-3 mb-4 text-luxury-neon">
                            <User size={24} />
                            <h2 className="text-xl font-black uppercase tracking-widest text-white">Identity</h2>
                        </div>

                        <div className="space-y-4">
                            <div>
                                <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest block mb-2">Display Name</label>
                                <input type="text" value={name} onChange={e => setName(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-xl p-4 text-white outline-none focus:border-luxury-neon transition-all" placeholder="Enter Name" />
                            </div>

                            <div>
                                <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest block mb-2">Biological Sex (For BMR)</label>
                                <div className="grid grid-cols-3 gap-2">
                                    {['Male', 'Female', 'Other'].map(g => (
                                        <button key={g} onClick={() => setGender(g as Gender)} className={`py-3 rounded-xl border text-xs font-bold transition-all ${gender === g ? 'bg-luxury-neon text-black border-luxury-neon' : 'bg-white/5 text-gray-400 border-white/10'}`}>
                                            {g}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div>
                                <label className="text-[10px] font-bold text-gray-500 uppercase tracking-widest block mb-2">Date of Birth</label>
                                <input type="date" value={dob} onChange={e => setDob(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-xl p-4 text-white outline-none focus:border-luxury-neon transition-all" />
                            </div>
                        </div>

                        <div className="pt-4 flex justify-end">
                            <button onClick={nextStep} disabled={!dob || !name} className="px-8 py-4 bg-white text-black font-black uppercase tracking-widest text-xs rounded-2xl flex items-center gap-2 disabled:opacity-50 hover:scale-105 active:scale-95 transition-all">
                                Next <ChevronRight size={16} />
                            </button>
                        </div>
                    </motion.div>
                )}

                {/* STEP 2: METRICS */}
                {step === 2 && (
                    <motion.div key="step2" initial={{ opacity: 0, x: 50 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -50 }} className="p-8 space-y-8">
                        <div className="flex items-center gap-3 mb-4 text-luxury-neon">
                            <Activity size={24} />
